import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { createClient } from '@supabase/supabase-js';
import { 
  User, UserStatus, Role, Capability, Wallet, Transaction, 
  RewardItem, Order, OrderStatus, TransactionType 
} from './types';
import { getDB, saveDB, INITIAL_DB } from './store';

// Pages & Components
import Login from './pages/Login';
import Register from './pages/Register';
import Dashboard from './pages/Dashboard';
import Store from './pages/Store';
import MyOrders from './pages/MyOrders';
import Leadership from './pages/Leadership';
import Approvals from './pages/Approvals';
import Admin from './pages/Admin';
import Sidebar from './components/Sidebar';
import Topbar from './components/Topbar';
import Toast, { ToastType } from './components/Toast';

const supabaseUrl = 'https://ghgyiscnzcwokillnlox.supabase.co';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImdoZ3lpc2NuemN3b2tpbGxubG94Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjUzNzgyMjYsImV4cCI6MjA4MDk1NDIyNn0.1qzhIJ7A0pfxl8cuHTqFnCAZ7cMIICfhuYKlfhkhchU';
const supabase = createClient(supabaseUrl, supabaseKey);

const App: React.FC = () => {
  const [db, setDb] = useState(INITIAL_DB);
  const [isLoading, setIsLoading] = useState(true);
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'LOGIN' | 'REGISTER' | 'DASHBOARD' | 'STORE' | 'MY_ORDERS' | 'LEADERSHIP' | 'APPROVALS' | 'ADMIN'>('LOGIN');
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  const showToast = useCallback((message: string, type: ToastType = 'info') => {
    setToast({ message, type });
  }, []);

  const syncWithCloud = useCallback(async (data: any) => {
    saveDB(data);
    try {
      await supabase
        .from('app_state')
        .upsert({ 
          id: 1, 
          content: data, 
          updated_at: new Date().toISOString() 
        }, { onConflict: 'id' });
    } catch (err) {
      console.error('Falha na sincronização:', err);
    }
  }, []);

  useEffect(() => {
    const initData = async () => {
      setIsLoading(true);
      try {
        const { data, error } = await supabase
          .from('app_state')
          .select('content')
          .eq('id', 1)
          .maybeSingle();

        if (!error && data?.content) {
          // Merge profundo básico para garantir que novas propriedades existam
          const merged = {
            ...INITIAL_DB,
            ...data.content,
            // Garante que arrays existam
            users: data.content.users || INITIAL_DB.users,
            wallets: data.content.wallets || INITIAL_DB.wallets,
            transactions: data.content.transactions || INITIAL_DB.transactions,
            rewardItems: data.content.rewardItems || INITIAL_DB.rewardItems,
            orders: data.content.orders || INITIAL_DB.orders,
          };
          setDb(merged);
          saveDB(merged);
        } else {
          setDb(getDB());
        }
      } catch (err) {
        setDb(getDB());
      } finally {
        setIsLoading(false);
      }
    };
    initData();
  }, []);

  useEffect(() => {
    if (!isLoading) {
      const savedUserId = localStorage.getItem('current_user_id');
      if (savedUserId) {
        const dbUser = db.users.find(u => u.id === savedUserId);
        if (dbUser && dbUser.status === UserStatus.ACTIVE) {
          setUser(dbUser);
          setView('DASHBOARD');
        }
      }
    }
  }, [isLoading, db.users]);

  const handleLogin = (u: User) => {
    if (u.status === UserStatus.PENDING) return showToast('Cadastro pendente.', 'warning');
    if (u.status === UserStatus.BLOCKED) return showToast('Conta bloqueada.', 'error');
    setUser(u);
    localStorage.setItem('current_user_id', u.id);
    setView('DASHBOARD');
    showToast(`Bem-vindo, ${u.name}!`, 'success');
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('current_user_id');
    setView('LOGIN');
  };

  const refreshDB = useCallback(() => {
    const current = getDB();
    setDb(current);
    syncWithCloud(current);
  }, [syncWithCloud]);

  const userWallet = useMemo(() => {
    const found = user ? db.wallets.find(w => w.userId === user.id) : null;
    return found || { userId: user?.id || '', balance: 0, donatableGold: 0, donatableSilver: 0, donatableBronze: 0 };
  }, [user, db.wallets]);

  if (isLoading) return (
    <div className="min-h-screen bg-black flex flex-col items-center justify-center">
      <div className="tampinha-container mb-8 scale-75">
        <div className="tampinha-serrilha animate-spin-slow"></div>
        <div className="tampinha-fundo-preto">
          <span className="text-yellow-500 font-black italic text-xl">S</span>
        </div>
      </div>
      <p className="text-yellow-500 font-black uppercase tracking-widest text-[10px] animate-pulse italic">Sincronizando Nuvem...</p>
    </div>
  );

  return (
    <div className="flex min-h-screen bg-black">
      {view !== 'LOGIN' && view !== 'REGISTER' && (
        <Sidebar currentView={view} setView={setView} capabilities={user?.capabilities || []} />
      )}
      <div className="flex-1 flex flex-col min-w-0">
        {view !== 'LOGIN' && view !== 'REGISTER' && (
          <Topbar user={user} wallet={userWallet} onLogout={handleLogout} />
        )}
        <main className="flex-1 p-4 md:p-8 overflow-y-auto bg-black">
          <div className="max-w-7xl mx-auto">
            {view === 'LOGIN' && <Login onLogin={handleLogin} onGoToRegister={() => setView('REGISTER')} db={db} onRefreshDB={refreshDB} showToast={showToast} />}
            {view === 'REGISTER' && <Register onGoToLogin={() => setView('LOGIN')} db={db} onRefreshDB={refreshDB} showToast={showToast} />}
            {view === 'DASHBOARD' && <Dashboard user={user!} db={db} setView={setView} />}
            {view === 'STORE' && <Store user={user!} db={db} onRefreshDB={refreshDB} showToast={showToast} />}
            {view === 'MY_ORDERS' && <MyOrders user={user!} db={db} />}
            {view === 'LEADERSHIP' && <Leadership user={user!} db={db} onRefreshDB={refreshDB} showToast={showToast} />}
            {view === 'APPROVALS' && <Approvals user={user!} db={db} onRefreshDB={refreshDB} showToast={showToast} />}
            {view === 'ADMIN' && <Admin user={user!} db={db} onRefreshDB={refreshDB} showToast={showToast} />}
          </div>
        </main>
      </div>
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { User, UserStatus, Capability, RewardItem, Wallet, CoinType, TransactionType } from '../types';
import { saveDB, addAuditLog, getDB } from '../store';
import { ToastType } from '../components/Toast';

interface AdminProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
  showToast: (msg: string, type: ToastType) => void;
}

const Admin: React.FC<AdminProps> = ({ user, db, onRefreshDB, showToast }) => {
  const [activeTab, setActiveTab] = useState<'USERS' | 'ITEMS'>('USERS');
  const [selectedUserForCarga, setSelectedUserForCarga] = useState<User | null>(null);
  const [cargaAmount, setCargaAmount] = useState<number>(0);

  const economicData = useMemo(() => {
    const rewardItems = db.rewardItems || [];
    const wallets = db.wallets || [];

    const totalStockValue = rewardItems.reduce((acc: number, item: RewardItem) => acc + ((item.cost || 0) * (item.stock || 0)), 0);

    const personalPoints = wallets.reduce((acc: number, w: Wallet) => acc + (w.balance || 0), 0);
    const donationPoints = wallets.reduce((acc: number, w: Wallet) => {
      return acc + ((w.donatableGold || 0) * 3) + ((w.donatableSilver || 0) * 2) + ((w.donatableBronze || 0) * 1);
    }, 0);

    const totalDistributedPoints = personalPoints + donationPoints;
    const balanceGap = totalStockValue - totalDistributedPoints;

    return { totalStockValue, totalDistributedPoints, balanceGap };
  }, [db.rewardItems, db.wallets]);

  const handleCargaMoedas = () => {
    if (!selectedUserForCarga || cargaAmount <= 0) return;

    let weight = 1;
    let coinType = CoinType.BRONZE;

    if (selectedUserForCarga.capabilities.includes(Capability.ADMIN) || selectedUserForCarga.capabilities.includes(Capability.GERENTE_FABRIL)) {
      weight = 3;
      coinType = CoinType.GOLD;
    } else if (selectedUserForCarga.capabilities.includes(Capability.GERENTE_AREA)) {
      weight = 2;
      coinType = CoinType.SILVER;
    }

    const totalPointsNeeded = cargaAmount * weight;

    if (totalPointsNeeded > economicData.balanceGap) {
      showToast(`Estoque insuficiente! Você precisa de ${totalPointsNeeded} pts, mas o sistema tem apenas ${economicData.balanceGap} pts livres.`, 'error');
      return;
    }

    const currentDb = getDB();
    const wallet = currentDb.wallets.find((w: any) => w.userId === selectedUserForCarga.id);

    if (wallet) {
      if (coinType === CoinType.GOLD) wallet.donatableGold = (wallet.donatableGold || 0) + cargaAmount;
      else if (coinType === CoinType.SILVER) wallet.donatableSilver = (wallet.donatableSilver || 0) + cargaAmount;
      else if (coinType === CoinType.BRONZE) wallet.donatableBronze = (wallet.donatableBronze || 0) + cargaAmount;

      currentDb.transactions.unshift({
        id: Math.random().toString(36).substr(2, 9),
        type: TransactionType.CREDIT,
        amount: totalPointsNeeded,
        coinType: coinType,
        fromUserId: 'SYSTEM',
        toUserId: selectedUserForCarga.id,
        reason: 'Carga de Verba para Distribuição',
        category: 'Verba Administrativa',
        createdAt: new Date().toISOString(),
        createdBy: user.id,
        isDonationVerba: true
      });

      saveDB(currentDb);
      onRefreshDB();
      showToast(`Verba de ${cargaAmount} moedas de ${coinType} carregada para ${selectedUserForCarga.name}`, 'success');
      setSelectedUserForCarga(null);
      setCargaAmount(0);
    }
  };

  const updateUserStatus = (u: User, status: UserStatus) => {
    const currentDb = getDB();
    const userInDb = currentDb.users.find((user: User) => user.id === u.id);
    if (userInDb) {
      userInDb.status = status;
      saveDB(currentDb);
      onRefreshDB();
    }
  };

  const toggleCapability = (u: User, cap: Capability) => {
    const currentDb = getDB();
    const userInDb = currentDb.users.find((user: User) => user.id === u.id);
    if (userInDb) {
      const jobCaps = [Capability.OPERADOR, Capability.SUPERVISOR_COORDENADOR, Capability.GERENTE_AREA, Capability.GERENTE_FABRIL, Capability.GENTE_GESTAO];
      if (userInDb.capabilities.includes(cap)) {
        userInDb.capabilities = userInDb.capabilities.filter((c: Capability) => c !== cap);
      } else {
        if (jobCaps.includes(cap)) userInDb.capabilities = userInDb.capabilities.filter(c => !jobCaps.includes(c));
        userInDb.capabilities.push(cap);
      }
      saveDB(currentDb);
      onRefreshDB();
    }
  };

  const sortedUsers = [...(db.users || [])].sort((a, b) => (a.status === UserStatus.PENDING ? -1 : 0));

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <header>
        <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter">Gestão Econômica</h1>
        <p className="text-zinc-500 text-xs font-bold uppercase tracking-widest mt-1 italic">Controle de Verba e Colaboradores.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className={`p-8 rounded-[2.5rem] border ${economicData.balanceGap < 0 ? 'bg-rose-500/10 border-rose-500/20' : 'bg-emerald-500/10 border-emerald-500/20'}`}>
          <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-1">Capacidade de Emissão</p>
          <div className="flex items-end gap-2">
            <span className={`text-4xl font-black italic tracking-tighter ${economicData.balanceGap < 0 ? 'text-rose-500' : 'text-emerald-500'}`}>
              {economicData.balanceGap || 0}
            </span>
            <span className="text-[10px] font-black text-zinc-600 uppercase mb-2">Pts Disponíveis</span>
          </div>
          <p className="text-[9px] text-zinc-500 mt-2 font-medium">Margem segura baseada no estoque real de brindes.</p>
        </div>

        <div className="p-8 rounded-[2.5rem] bg-zinc-900/40 border border-zinc-800">
          <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-1">Passivo Circulante</p>
          <div className="flex items-end gap-2">
            <span className="text-4xl font-black text-white italic tracking-tighter">{economicData.totalDistributedPoints || 0}</span>
            <span className="text-[10px] font-black text-zinc-600 uppercase mb-2">Pts Emitidos</span>
          </div>
        </div>

        <div className="p-8 rounded-[2.5rem] bg-zinc-900/40 border border-zinc-800">
          <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-1">Patrimônio de Brindes</p>
          <div className="flex items-end gap-2">
            <span className="text-4xl font-black text-yellow-500 italic tracking-tighter">{economicData.totalStockValue || 0}</span>
            <span className="text-[10px] font-black text-zinc-600 uppercase mb-2">Pts Reais</span>
          </div>
        </div>
      </div>

      <div className="flex gap-4 border-b border-zinc-800">
        <button onClick={() => setActiveTab('USERS')} className={`px-6 py-4 font-black text-[10px] uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === 'USERS' ? 'border-yellow-500 text-yellow-500' : 'border-transparent text-zinc-600 hover:text-white'}`}>Colaboradores</button>
        <button onClick={() => setActiveTab('ITEMS')} className={`px-6 py-4 font-black text-[10px] uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === 'ITEMS' ? 'border-yellow-500 text-yellow-500' : 'border-transparent text-zinc-600 hover:text-white'}`}>Estoque</button>
      </div>

      {activeTab === 'USERS' && (
        <div className="bg-zinc-900/40 border border-zinc-800 rounded-[2.5rem] overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-black/40">
              <tr>
                <th className="px-8 py-4 text-[10px] font-black text-zinc-600 uppercase tracking-widest">Colaborador</th>
                <th className="px-8 py-4 text-[10px] font-black text-zinc-600 uppercase tracking-widest text-center">Perfil</th>
                <th className="px-8 py-4 text-[10px] font-black text-zinc-600 uppercase tracking-widest text-right">Ações de Verba</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-zinc-800">
              {sortedUsers.map((u: User) => {
                const isLeader = u.capabilities.some(c => [Capability.SUPERVISOR_COORDENADOR, Capability.GERENTE_AREA, Capability.GERENTE_FABRIL, Capability.GENTE_GESTAO, Capability.ADMIN].includes(c));
                return (
                  <tr key={u.id} className="hover:bg-white/5 transition-colors">
                    <td className="px-8 py-6">
                      <p className="font-black text-white uppercase italic tracking-tighter">{u.name}</p>
                      <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest">ID: {u.corporateId}</p>
                    </td>
                    <td className="px-8 py-6">
                      <div className="flex flex-wrap gap-2 justify-center">
                        {[Capability.OPERADOR, Capability.SUPERVISOR_COORDENADOR, Capability.GERENTE_AREA, Capability.GERENTE_FABRIL, Capability.GENTE_GESTAO].map(cap => (
                          <button key={cap} onClick={() => toggleCapability(u, cap)} className={`px-3 py-1.5 rounded-xl text-[8px] border font-black uppercase tracking-widest transition-all ${u.capabilities.includes(cap) ? 'bg-yellow-500 text-black border-yellow-500' : 'bg-black text-zinc-600 border-zinc-800'}`}>{cap.split('_').join(' ')}</button>
                        ))}
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <div className="flex items-center justify-end gap-2">
                        {isLeader && u.status === UserStatus.ACTIVE && (
                          <button onClick={() => setSelectedUserForCarga(u)} className="bg-emerald-500/20 text-emerald-500 border border-emerald-500/30 p-2.5 rounded-xl hover:bg-emerald-500 hover:text-black transition-all">
                            <i className="fa-solid fa-bolt mr-2"></i> CARREGAR VERBA
                          </button>
                        )}
                        <button onClick={() => updateUserStatus(u, u.status === UserStatus.BLOCKED ? UserStatus.ACTIVE : UserStatus.BLOCKED)} className="w-10 h-10 rounded-xl bg-zinc-800 text-zinc-500 flex items-center justify-center hover:text-white">
                          <i className={`fa-solid ${u.status === UserStatus.BLOCKED ? 'fa-unlock' : 'fa-lock'}`}></i>
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}

      {selectedUserForCarga && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="w-full max-w-md bg-zinc-900 border border-zinc-800 rounded-[3rem] p-10 shadow-2xl animate-in zoom-in duration-300">
            <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter text-center mb-6">Distribuir Verba de Gestão</h3>
            <p className="text-center text-[10px] text-zinc-500 font-bold uppercase mb-8">Líder: {selectedUserForCarga.name}</p>
            <div className="space-y-6">
              <input type="number" autoFocus className="w-full p-5 bg-black border border-zinc-800 text-white text-3xl font-black rounded-3xl text-center outline-none focus:border-yellow-500" value={cargaAmount || ''} onChange={e => setCargaAmount(Number(e.target.value))} />
              <div className="flex gap-3">
                <button onClick={() => setSelectedUserForCarga(null)} className="flex-1 py-4 text-zinc-500 font-black text-[10px] uppercase">Cancelar</button>
                <button onClick={handleCargaMoedas} className="flex-[2] py-4 bg-yellow-500 text-black rounded-2xl font-black text-[10px] uppercase tracking-widest">Liberar Moedas</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Admin;

import React, { useState, useMemo } from 'react';
import { User, UserStatus, Capability, RewardItem, Wallet, CoinType, TransactionType } from '../types';
import { saveDB, addAuditLog, getDB } from '../store';
import { ToastType } from '../components/Toast';

interface AdminProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
  showToast: (msg: string, type: ToastType) => void;
}

const Admin: React.FC<AdminProps> = ({ user, db, onRefreshDB, showToast }) => {
  const [activeTab, setActiveTab] = useState<'USERS' | 'ITEMS'>('USERS');

  const economicData = useMemo(() => {
    const rewardItems = db.rewardItems || [];
    const wallets = db.wallets || [];
    const totalStockValue = rewardItems.reduce((acc: number, item: RewardItem) => acc + ((item.cost || 0) * (item.stock || 0)), 0);
    const personalPoints = wallets.reduce((acc: number, w: Wallet) => acc + (w.balance || 0), 0);
    const donationPoints = wallets.reduce((acc: number, w: Wallet) => {
      return acc + ((w.donatableGold || 0) * 3) + ((w.donatableSilver || 0) * 2) + ((w.donatableBronze || 0) * 1);
    }, 0);
    return { totalStockValue, totalDistributedPoints: personalPoints + donationPoints, balanceGap: totalStockValue - (personalPoints + donationPoints) };
  }, [db.rewardItems, db.wallets]);

  const handleAdjustVerba = (targetUser: User, delta: number) => {
    const currentDb = getDB();
    const wallet = currentDb.wallets.find((w: any) => w.userId === targetUser.id);
    if (!wallet) return;

    let coinType = CoinType.BRONZE;
    let weight = 1;

    if (targetUser.capabilities.includes(Capability.ADMIN) || targetUser.capabilities.includes(Capability.GERENTE_FABRIL)) {
      coinType = CoinType.GOLD; weight = 3;
    } else if (targetUser.capabilities.includes(Capability.GERENTE_AREA)) {
      coinType = CoinType.SILVER; weight = 2;
    }

    const pointsDelta = delta * weight;
    if (delta > 0 && pointsDelta > economicData.balanceGap) {
      showToast('Limite de emissão atingido pelo estoque!', 'error');
      return;
    }

    // Atualiza moeda específica
    if (coinType === CoinType.GOLD) wallet.donatableGold = Math.max(0, (wallet.donatableGold || 0) + delta);
    else if (coinType === CoinType.SILVER) wallet.donatableSilver = Math.max(0, (wallet.donatableSilver || 0) + delta);
    else wallet.donatableBronze = Math.max(0, (wallet.donatableBronze || 0) + delta);

    currentDb.transactions.unshift({
      id: Math.random().toString(36).substr(2, 9),
      type: delta > 0 ? TransactionType.CREDIT : TransactionType.DEBIT,
      amount: Math.abs(pointsDelta),
      coinType,
      fromUserId: 'SYSTEM',
      toUserId: targetUser.id,
      reason: 'Ajuste Administrativo de Verba',
      category: 'Administração',
      createdAt: new Date().toISOString(),
      createdBy: user.id,
      isDonationVerba: true
    });

    saveDB(currentDb);
    onRefreshDB();
  };

  const handleAdjustSaldo = (targetUser: User, delta: number) => {
    const currentDb = getDB();
    const wallet = currentDb.wallets.find((w: any) => w.userId === targetUser.id);
    if (!wallet) return;

    if (delta > 0 && delta > economicData.balanceGap) {
      showToast('Estoque insuficiente para este ajuste!', 'error');
      return;
    }

    wallet.balance = Math.max(0, (wallet.balance || 0) + delta);

    currentDb.transactions.unshift({
      id: Math.random().toString(36).substr(2, 9),
      type: delta > 0 ? TransactionType.CREDIT : TransactionType.DEBIT,
      amount: Math.abs(delta),
      fromUserId: 'SYSTEM',
      toUserId: targetUser.id,
      reason: 'Correção de Distribuição / Ajuste Manual',
      category: 'Administração',
      createdAt: new Date().toISOString(),
      createdBy: user.id
    });

    saveDB(currentDb);
    onRefreshDB();
  };

  const sortedUsers = [...(db.users || [])].sort((a, b) => (a.status === UserStatus.PENDING ? -1 : 0));

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <header>
        <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter leading-none">Gestão Econômica</h1>
        <p className="text-zinc-500 text-[10px] font-black uppercase tracking-[0.2em] mt-2 italic">Ajuste de Fluxo e Saneamento de Saldos.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className={`p-6 rounded-[2rem] border transition-colors ${economicData.balanceGap < 0 ? 'bg-rose-500/10 border-rose-500/20' : 'bg-emerald-500/10 border-emerald-500/20'}`}>
          <p className="text-[9px] font-black text-zinc-500 uppercase tracking-widest mb-1">Capacidade de Emissão</p>
          <div className="flex items-baseline gap-2">
            <span className={`text-4xl font-black italic tracking-tighter ${economicData.balanceGap < 0 ? 'text-rose-500' : 'text-emerald-500'}`}>{economicData.balanceGap || 0}</span>
            <span className="text-[8px] font-black text-zinc-600 uppercase">Pts</span>
          </div>
        </div>
        <div className="p-6 rounded-[2rem] bg-zinc-900 border border-zinc-800">
