          <div className="flex items-baseline gap-2">
            <span className={`text-4xl font-black italic tracking-tighter ${economicData.balanceGap < 0 ? 'text-rose-500' : 'text-emerald-500'}`}>{economicData.balanceGap || 0}</span>
            <span className="text-[8px] font-black text-zinc-600 uppercase">Pts</span>
          </div>
        </div>
        <div className="p-6 rounded-[2rem] bg-zinc-900 border border-zinc-800">
          <p className="text-[9px] font-black text-zinc-500 uppercase tracking-widest mb-1">Passivo (Emitido)</p>
          <div className="flex items-baseline gap-2 text-white">
            <span className="text-4xl font-black italic tracking-tighter">{economicData.totalDistributedPoints || 0}</span>
            <span className="text-[8px] font-black text-zinc-600 uppercase">Pts</span>
          </div>
        </div>
        <div className="p-6 rounded-[2rem] bg-zinc-900 border border-zinc-800">
          <p className="text-[9px] font-black text-zinc-500 uppercase tracking-widest mb-1">Patrimônio Brindes</p>
          <div className="flex items-baseline gap-2 text-yellow-500">
            <span className="text-4xl font-black italic tracking-tighter">{economicData.totalStockValue || 0}</span>
            <span className="text-[8px] font-black text-zinc-600 uppercase">Pts</span>
          </div>
        </div>
      </div>

      <div className="bg-zinc-900/40 border border-zinc-800 rounded-[3rem] overflow-hidden">
        <div className="p-8 border-b border-zinc-800 flex justify-between items-center bg-black/20">
          <h2 className="font-black text-white italic uppercase tracking-tighter text-xl">Colaboradores</h2>
          <div className="flex gap-2">
             <div className="flex items-center gap-2 px-3 py-1 bg-yellow-500/10 rounded-full border border-yellow-500/20">
                <div className="w-1.5 h-1.5 rounded-full bg-yellow-500"></div>
                <span className="text-[8px] font-black text-yellow-500 uppercase tracking-widest">Ajuste de Verba (Líder)</span>
             </div>
             <div className="flex items-center gap-2 px-3 py-1 bg-zinc-500/10 rounded-full border border-zinc-800">
                <div className="w-1.5 h-1.5 rounded-full bg-white"></div>
                <span className="text-[8px] font-black text-zinc-500 uppercase tracking-widest">Correção de Saldo (Receptor)</span>
             </div>
