            <form onSubmit={handleSaveItem} className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-zinc-500 uppercase ml-1">Nome do Brinde</label>
                  <input name="name" defaultValue={itemToEdit?.name || ''} required className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl focus:border-yellow-500 outline-none font-bold" />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-zinc-500 uppercase ml-1">Categoria</label>
                  <input name="category" defaultValue={itemToEdit?.category || ''} required className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl focus:border-yellow-500 outline-none font-bold" />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-zinc-500 uppercase ml-1">Foto do Produto (Upload)</label>
                <div className="flex items-center gap-4">
                  <div className="w-24 h-24 rounded-2xl bg-black border border-zinc-800 overflow-hidden flex items-center justify-center">
                    {previewUrl ? (
                      <img src={previewUrl} className="w-full h-full object-cover" />
                    ) : (
                      <i className="fa-solid fa-camera text-zinc-700 text-2xl"></i>
                    )}
                  </div>
                  <label className="flex-1 cursor-pointer">
                    <div className="w-full p-6 bg-black border-2 border-dashed border-zinc-800 text-zinc-500 rounded-2xl hover:border-yellow-500 hover:text-white transition-all text-center">
                      <i className="fa-solid fa-cloud-arrow-up text-xl mb-2 block"></i>
                      <span className="text-[9px] font-black uppercase tracking-widest">Selecionar Foto Real</span>
                    </div>
                    <input type="file" accept="image/*" className="hidden" onChange={handleFileChange} />
                  </label>
                </div>
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-zinc-500 uppercase ml-1">Descrição Curta</label>
                <textarea name="description" defaultValue={itemToEdit?.description || ''} className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl focus:border-yellow-500 outline-none" rows={2}></textarea>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-zinc-500 uppercase ml-1">Custo (Pontos)</label>
                  <input type="number" name="cost" defaultValue={itemToEdit?.cost || 10} required className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl focus:border-yellow-500 outline-none font-black text-xl italic" />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-zinc-500 uppercase ml-1">Estoque Inicial</label>
                  <div className="flex items-center bg-black border border-zinc-800 rounded-2xl p-1 gap-1 h-[60px] focus-within:border-yellow-500">
                    <button type="button" onClick={() => setModalStock(Math.max(0, modalStock - 1))} className="w-10 h-10 flex items-center justify-center text-zinc-600 hover:text-rose-500 rounded-xl transition-all">
                      <i className="fa-solid fa-minus"></i>
                    </button>
                    <input 
                      type="number" 
                      className="flex-1 bg-transparent text-center text-2xl font-black text-white italic outline-none" 
                      value={modalStock} 
                      onChange={(e) => setModalStock(parseInt(e.target.value) || 0)}
                    />
                    <button type="button" onClick={() => setModalStock(modalStock + 1)} className="w-10 h-10 flex items-center justify-center text-emerald-500 hover:bg-emerald-500/5 rounded-xl transition-all">
                      <i className="fa-solid fa-plus"></i>
                    </button>
                  </div>
                </div>
              </div>

              <button 
                type="submit" 
                disabled={isUploading}
                className={`w-full py-5 rounded-[1.5rem] font-black text-xs uppercase tracking-widest transition-all shadow-lg flex items-center justify-center gap-3 ${isUploading ? 'bg-zinc-800 text-zinc-500' : 'bg-yellow-500 text-black hover:bg-yellow-400 shadow-yellow-500/20'}`}
              >
                {isUploading ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-cloud-arrow-up"></i>}
                {isUploading ? 'ENVIANDO FOTO...' : (itemToEdit ? 'SALVAR ALTERAÇÕES' : 'CADASTRAR BRINDE')}
              </button>
            </form>
          </div>
        </div>
      )}

      {/* MODAL DE GESTÃO DE USUÁRIO (PERMISSÕES) */}
      {userToEdit && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-xl z-[100] flex items-center justify-center p-4 overflow-y-auto">
          <div className="w-full max-w-2xl bg-zinc-900 border border-zinc-800 rounded-[3rem] p-10 shadow-2xl animate-in zoom-in duration-300 my-auto">
            <div className="flex justify-between items-start mb-10">
              <div>
                <h3 className="text-3xl font-black text-white italic uppercase tracking-tighter leading-none">Gestão de Colaborador</h3>
                <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest mt-2">{userToEdit.name} • {userToEdit.corporateId}</p>
              </div>
              <button onClick={() => setUserToEdit(null)} className="w-10 h-10 rounded-full bg-zinc-800 text-zinc-400 hover:text-white flex items-center justify-center transition-colors"><i className="fa-solid fa-xmark"></i></button>
            </div>

            <div className="space-y-10">
              {userToEdit.status === UserStatus.PENDING && (
                <div className="bg-yellow-500/10 border border-yellow-500/20 p-8 rounded-[2rem] flex flex-col md:flex-row items-center justify-between gap-6 shadow-[0_0_30px_rgba(234,179,8,0.05)]">
                  <div>
                    <h4 className="text-yellow-500 font-black uppercase italic tracking-tighter text-lg">Aprovação Pendente</h4>
                    <p className="text-[10px] text-zinc-400 font-bold uppercase tracking-widest">Colaborador aguardando liberação de acesso.</p>
                  </div>
                  <button onClick={() => approveUser(userToEdit)} className="w-full md:w-auto bg-yellow-500 text-black px-10 py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-yellow-400 transition-all shadow-lg">ATIVAR COLABORADOR</button>
                </div>
              )}

              <div className="space-y-4">
                <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Perfil Profissional (Cargo)</label>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2">
                  {[
                    { cap: Capability.OPERADOR, label: 'Operador' },
                    { cap: Capability.SUPERVISOR_COORDENADOR, label: 'Supervisor' },
                    { cap: Capability.GERENTE_AREA, label: 'Gerente Área' },
                    { cap: Capability.GERENTE_FABRIL, label: 'Gerente Fabril' },
                    { cap: Capability.GENTE_GESTAO, label: 'Gente & Gestão' },
                  ].map(role => (
                    <button key={role.cap} onClick={() => toggleCapability(userToEdit, role.cap)} className={`px-4 py-4 rounded-2xl border font-black text-[9px] uppercase tracking-widest transition-all ${userToEdit.capabilities.includes(role.cap) ? 'bg-white text-black border-white' : 'bg-black text-zinc-600 border-zinc-800 hover:border-zinc-500'}`}>{role.label}</button>
                  ))}
                </div>
              </div>

              <div className="space-y-4">
                <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Privilégios Administrativos</label>
                <button onClick={() => toggleCapability(userToEdit, Capability.ADMIN)} className={`w-full p-6 rounded-[2rem] border flex items-center gap-4 transition-all ${userToEdit.capabilities.includes(Capability.ADMIN) ? 'bg-yellow-500/10 border-yellow-500 text-yellow-500 shadow-lg' : 'bg-black text-zinc-600 border-zinc-800'}`}>
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${userToEdit.capabilities.includes(Capability.ADMIN) ? 'bg-yellow-500 text-black' : 'bg-zinc-900 text-zinc-700'}`}><i className="fa-solid fa-shield-halved"></i></div>
                  <div className="text-left">
                    <p className="font-black uppercase italic text-xs tracking-tighter">Administrador Master</p>
                    <p className="text-[8px] font-bold uppercase tracking-widest opacity-60">Acesso total à gestão econômica, usuários e estoque.</p>
                  </div>
                </button>
              </div>

              <div className="pt-8 border-t border-zinc-800 flex justify-end">
                 <button onClick={() => setUserToEdit(null)} className="px-12 py-4 bg-zinc-800 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-zinc-700 transition-all">Concluir Ajustes</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Admin;

import React, { useState, useMemo, useEffect } from 'react';
import { User, UserStatus, Capability, RewardItem, Wallet, CoinType, TransactionType } from '../types';
import { saveDB, addAuditLog, getDB } from '../store';
import { ToastType } from '../components/Toast';
import { supabase } from '../App';

interface AdminProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
  showToast: (msg: string, type: ToastType) => void;
}

const Admin: React.FC<AdminProps> = ({ user, db, onRefreshDB, showToast }) => {
  const [activeTab, setActiveTab] = useState<'USERS' | 'ITEMS'>('USERS');
  const [userToEdit, setUserToEdit] = useState<User | null>(null);
  const [itemToEdit, setItemToEdit] = useState<RewardItem | null>(null);
  const [isAddingItem, setIsAddingItem] = useState(false);

  // Estados para o modal de item
  const [modalStock, setModalStock] = useState(0);
  const [isUploading, setIsUploading] = useState(false);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string>('');

  // Estados para o modal de edição de usuário
  const [editUserName, setEditUserName] = useState('');
  const [editUserId, setEditUserId] = useState('');
  const [editUserPassword, setEditUserPassword] = useState('');

  // Sincroniza o estoque do modal quando o item a editar muda
  useEffect(() => {
    if (itemToEdit) {
      setModalStock(itemToEdit.stock || 0);
      setPreviewUrl(itemToEdit.imageUrl || '');
    } else if (isAddingItem) {
      setModalStock(0);
      setPreviewUrl('');
    }
    setSelectedFile(null);
  }, [itemToEdit, isAddingItem]);

  // Sincroniza os dados do usuário no modal de edição
  useEffect(() => {
    if (userToEdit) {
      setEditUserName(userToEdit.name);
      setEditUserId(userToEdit.corporateId);
      setEditUserPassword(userToEdit.passwordHash); // No sistema atual, passwordHash armazena a senha diretamente
    }
  }, [userToEdit]);

  const economicData = useMemo(() => {
    const rewardItems = db.rewardItems || [];
    const wallets = db.wallets || [];
    const totalStockValue = rewardItems.reduce((acc: number, item: RewardItem) => acc + ((item.cost || 0) * (item.stock || 0)), 0);
    const personalPoints = wallets.reduce((acc: number, w: Wallet) => acc + (w.balance || 0), 0);
    const donationPoints = wallets.reduce((acc: number, w: Wallet) => {
      return acc + ((w.donatableGold || 0) * 3) + ((w.donatableSilver || 0) * 2) + ((w.donatableBronze || 0) * 1);
    }, 0);
    return { totalStockValue, totalDistributedPoints: personalPoints + donationPoints, balanceGap: totalStockValue - (personalPoints + donationPoints) };
  }, [db.rewardItems, db.wallets]);

  // --- GESTÃO DE USUÁRIOS ---
  const handleUpdateUserData = () => {
    if (!userToEdit) return;

    const currentDb = getDB();
    const userInDb = currentDb.users.find((u: User) => u.id === userToEdit.id);

    if (userInDb) {
      // Verifica se o ID corporativo novo já existe em outro usuário
      const idExists = currentDb.users.some((u: User) => u.corporateId === editUserId && u.id !== userToEdit.id);
      if (idExists) {
        showToast('Este ID Corporativo já pertence a outro colaborador.', 'error');
        return;
      }

      userInDb.name = editUserName;
      userInDb.corporateId = editUserId;
      userInDb.passwordHash = editUserPassword;

      saveDB(currentDb);
      onRefreshDB();
      setUserToEdit({ ...userInDb });
      showToast('Dados do colaborador atualizados!', 'success');
    }
  };

  const handleAdjustVerba = (targetUser: User, newValue: number) => {
    const currentDb = getDB();
    const wallet = currentDb.wallets.find((w: any) => w.userId === targetUser.id);
    if (!wallet) return;
    let weight = 1;
    let coinType = CoinType.BRONZE;
    if (targetUser.capabilities.includes(Capability.ADMIN) || targetUser.capabilities.includes(Capability.GERENTE_FABRIL)) { coinType = CoinType.GOLD; weight = 3; }
    else if (targetUser.capabilities.includes(Capability.GERENTE_AREA)) { coinType = CoinType.SILVER; weight = 2; }
    const currentVal = coinType === CoinType.GOLD ? (wallet.donatableGold || 0) : coinType === CoinType.SILVER ? (wallet.donatableSilver || 0) : (wallet.donatableBronze || 0);
    const delta = newValue - currentVal;
    if (delta > 0 && (delta * weight) > economicData.balanceGap) { showToast('Limite de emissão atingido!', 'error'); return; }
    if (coinType === CoinType.GOLD) wallet.donatableGold = Math.max(0, newValue);
    else if (coinType === CoinType.SILVER) wallet.donatableSilver = Math.max(0, newValue);
    else wallet.donatableBronze = Math.max(0, newValue);
    if (delta !== 0) {
      currentDb.transactions.unshift({ id: Math.random().toString(36).substr(2, 9), type: delta > 0 ? TransactionType.CREDIT : TransactionType.DEBIT, amount: Math.abs(delta * weight), coinType, fromUserId: 'SYSTEM', toUserId: targetUser.id, reason: 'Ajuste Admin Verba', category: 'Administração', createdAt: new Date().toISOString(), createdBy: user.id, isDonationVerba: true });
      saveDB(currentDb); onRefreshDB();
    }
  };

  const handleAdjustSaldo = (targetUser: User, newValue: number) => {
    const currentDb = getDB();
    const wallet = currentDb.wallets.find((w: any) => w.userId === targetUser.id);
    if (!wallet) return;
    const delta = newValue - (wallet.balance || 0);
    if (delta > 0 && delta > economicData.balanceGap) { showToast('Estoque insuficiente!', 'error'); return; }
    wallet.balance = Math.max(0, newValue);
    if (delta !== 0) {
      currentDb.transactions.unshift({ id: Math.random().toString(36).substr(2, 9), type: delta > 0 ? TransactionType.CREDIT : TransactionType.DEBIT, amount: Math.abs(delta), fromUserId: 'SYSTEM', toUserId: targetUser.id, reason: 'Correção de Saldo Admin', category: 'Administração', createdAt: new Date().toISOString(), createdBy: user.id });
      saveDB(currentDb); onRefreshDB();
    }
  };

  const approveUser = (u: User) => {
    const currentDb = getDB();
    const userInDb = currentDb.users.find((user: User) => user.id === u.id);
    if (userInDb) { userInDb.status = UserStatus.ACTIVE; saveDB(currentDb); onRefreshDB(); setUserToEdit({ ...userInDb }); showToast(`${u.name} ativado!`, 'success'); }
  };

  const toggleCapability = (u: User, cap: Capability) => {
    const currentDb = getDB();
    const userInDb = currentDb.users.find((user: User) => user.id === u.id);
    if (userInDb) {
      const jobRoles = [Capability.OPERADOR, Capability.SUPERVISOR_COORDENADOR, Capability.GERENTE_AREA, Capability.GERENTE_FABRIL, Capability.GENTE_GESTAO];
      if (jobRoles.includes(cap)) { userInDb.capabilities = userInDb.capabilities.filter(c => !jobRoles.includes(c)); userInDb.capabilities.push(cap); }
      else { if (userInDb.capabilities.includes(cap)) { userInDb.capabilities = userInDb.capabilities.filter(c => c !== cap); } else { userInDb.capabilities.push(cap); } }
      saveDB(currentDb); onRefreshDB(); setUserToEdit({ ...userInDb });
    }
  };

  // --- GESTÃO DE ITENS / ESTOQUE ---
  const handleUpdateItemStock = (itemId: string, newStock: number) => {
    const currentDb = getDB();
    const item = currentDb.rewardItems.find(i => i.id === itemId);
    if (item) {
      item.stock = Math.max(0, newStock);
      saveDB(currentDb);
      onRefreshDB();
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedFile(file);
      const url = URL.createObjectURL(file);
      setPreviewUrl(url);
    }
  };

  const handleSaveItem = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsUploading(true);

    try {
      const formData = new FormData(e.currentTarget as HTMLFormElement);
      let finalImageUrl = itemToEdit?.imageUrl || '';

      // Upload para o Supabase se um novo arquivo foi selecionado
      if (selectedFile) {
        const fileExt = selectedFile.name.split('.').pop();
        const fileName = `${Math.random().toString(36).substr(2, 9)}.${fileExt}`;
        const filePath = `items/${fileName}`;

        const { error: uploadError } = await supabase.storage
          .from('reward-images')
          .upload(filePath, selectedFile);

        if (uploadError) throw uploadError;

        const { data: { publicUrl } } = supabase.storage
          .from('reward-images')
          .getPublicUrl(filePath);

        finalImageUrl = publicUrl;
      }

      const itemData = {
        name: formData.get('name') as string,
        description: formData.get('description') as string,
        imageUrl: finalImageUrl,
        cost: Number(formData.get('cost')),
        stock: modalStock,
        category: formData.get('category') as string,
        isActive: true,
      };

      const currentDb = getDB();
      if (itemToEdit) {
        const idx = currentDb.rewardItems.findIndex(i => i.id === itemToEdit.id);
        currentDb.rewardItems[idx] = { ...itemToEdit, ...itemData };
        showToast('Item atualizado com sucesso!', 'success');
      } else {
        currentDb.rewardItems.push({ ...itemData, id: Math.random().toString(36).substr(2, 9) });
        showToast('Novo item adicionado ao catálogo!', 'success');
      }

      saveDB(currentDb);
      onRefreshDB();
      setItemToEdit(null);
      setIsAddingItem(false);
    } catch (err: any) {
      console.error(err);
      showToast('Erro ao salvar item ou fazer upload: ' + err.message, 'error');
    } finally {
      setIsUploading(false);
    }
  };

  const sortedUsers = [...(db.users || [])].sort((a, b) => (a.status === UserStatus.PENDING ? -1 : 1));

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter leading-none">Painel de Controle</h1>
          <p className="text-zinc-500 text-[10px] font-black uppercase tracking-[0.2em] mt-2 italic">Gestão Econômica e Inventário de Brindes.</p>
        </div>
        <div className="flex gap-2 bg-zinc-900/50 p-2 rounded-2xl w-fit border border-zinc-800">
          <button onClick={() => setActiveTab('USERS')} className={`px-8 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeTab === 'USERS' ? 'bg-yellow-500 text-black shadow-lg shadow-yellow-500/10' : 'text-zinc-500 hover:text-white'}`}>Colaboradores</button>
          <button onClick={() => setActiveTab('ITEMS')} className={`px-8 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeTab === 'ITEMS' ? 'bg-white text-black shadow-lg shadow-white/10' : 'text-zinc-500 hover:text-white'}`}>Gerenciar Estoque</button>
        </div>
      </header>

      {/* CARDS ECONÔMICOS */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className={`p-6 rounded-[2rem] border transition-colors ${economicData.balanceGap < 0 ? 'bg-rose-500/10 border-rose-500/20' : 'bg-emerald-500/10 border-emerald-500/20'}`}>
          <p className="text-[9px] font-black text-zinc-500 uppercase tracking-widest mb-1">Capacidade de Emissão (Estoque Livre)</p>
          <div className="flex items-baseline gap-2">
            <span className={`text-4xl font-black italic tracking-tighter ${economicData.balanceGap < 0 ? 'text-rose-500' : 'text-emerald-500'}`}>{economicData.balanceGap || 0}</span>
            <span className="text-[8px] font-black text-zinc-600 uppercase">Pts</span>
          </div>
        </div>
        <div className="p-6 rounded-[2rem] bg-zinc-900 border border-zinc-800">
          <p className="text-[9px] font-black text-zinc-500 uppercase tracking-widest mb-1">Passivo (Moedas em Mãos)</p>
          <div className="flex items-baseline gap-2 text-white">
            <span className="text-4xl font-black italic tracking-tighter">{economicData.totalDistributedPoints || 0}</span>
            <span className="text-[8px] font-black text-zinc-600 uppercase">Pts</span>
          </div>
        </div>
        <div className="p-6 rounded-[2rem] bg-zinc-900 border border-zinc-800">
          <p className="text-[9px] font-black text-zinc-500 uppercase tracking-widest mb-1">Patrimônio Brindes (Total em Itens)</p>
          <div className="flex items-baseline gap-2 text-yellow-500">
            <span className="text-4xl font-black italic tracking-tighter">{economicData.totalStockValue || 0}</span>
            <span className="text-[8px] font-black text-zinc-600 uppercase">Pts</span>
          </div>
        </div>
      </div>

      {activeTab === 'USERS' ? (
        <div className="bg-zinc-900/40 border border-zinc-800 rounded-[3rem] overflow-hidden">
          <div className="p-8 border-b border-zinc-800 flex justify-between items-center bg-black/20 text-white">
            <h2 className="font-black italic uppercase tracking-tighter text-xl text-white">Lista de Colaboradores</h2>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-black/40">
                <tr>
                  <th className="px-8 py-5 text-[9px] font-black text-zinc-600 uppercase tracking-[0.2em]">Colaborador</th>
                  <th className="px-8 py-5 text-[9px] font-black text-zinc-600 uppercase tracking-[0.2em] text-center">Verba Liderança</th>
                  <th className="px-8 py-5 text-[9px] font-black text-zinc-600 uppercase tracking-[0.2em] text-center">Saldo Loja</th>
                  <th className="px-8 py-5 text-[9px] font-black text-zinc-600 uppercase tracking-[0.2em] text-right">Ações</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-zinc-800">
                {sortedUsers.map((u: User) => {
                  const wallet = db.wallets.find((w: any) => w.userId === u.id) || { balance: 0, donatableGold: 0, donatableSilver: 0, donatableBronze: 0 };
                  const isLeader = u.capabilities.some(c => [Capability.SUPERVISOR_COORDENADOR, Capability.GERENTE_AREA, Capability.GERENTE_FABRIL, Capability.GENTE_GESTAO, Capability.ADMIN].includes(c));
                  const coinValue = u.capabilities.includes(Capability.ADMIN) || u.capabilities.includes(Capability.GERENTE_FABRIL) ? (wallet.donatableGold || 0) : u.capabilities.includes(Capability.GERENTE_AREA) ? (wallet.donatableSilver || 0) : (wallet.donatableBronze || 0);
                  return (
                    <tr key={u.id} className="hover:bg-white/[0.02] transition-colors">
                      <td className="px-8 py-6">
                        <p className="font-black text-white uppercase italic tracking-tighter leading-none mb-1">{u.name}</p>
                        <div className="flex items-center gap-2">
                          <span className="text-[9px] text-zinc-600 font-bold uppercase tracking-widest">{u.corporateId}</span>
                          {u.status === UserStatus.PENDING && <span className="text-[7px] bg-yellow-500 text-black px-1.5 py-0.5 rounded font-black uppercase">Aprovação Pendente</span>}
                        </div>
                      </td>
                      <td className="px-8 py-6">
                        <div className="flex justify-center">
                          {isLeader ? (
                            <div className="flex items-center bg-black border border-zinc-800 rounded-2xl overflow-hidden p-1 gap-1 shadow-inner focus-within:border-yellow-500/50 transition-all">
                              <button onClick={() => handleAdjustVerba(u, Math.max(0, coinValue - 1))} className="w-8 h-8 flex items-center justify-center text-zinc-600 hover:text-white hover:bg-zinc-800 rounded-xl"><i className="fa-solid fa-minus text-[10px]"></i></button>
                              <div className="min-w-[50px] text-center">
                                <input type="number" className="w-12 bg-transparent text-center text-lg font-black text-yellow-500 italic leading-none outline-none" value={coinValue} onChange={(e) => handleAdjustVerba(u, parseInt(e.target.value) || 0)} />
                                <p className="text-[7px] text-zinc-600 font-black uppercase mt-0.5">Moedas</p>
                              </div>
                              <button onClick={() => handleAdjustVerba(u, coinValue + 1)} className="w-8 h-8 flex items-center justify-center text-yellow-500 hover:bg-yellow-500/10 rounded-xl"><i className="fa-solid fa-plus text-[10px]"></i></button>
                            </div>
                          ) : <span className="text-[9px] text-zinc-700 font-black uppercase italic">Sem Perfil Líder</span>}
                        </div>
                      </td>
                      <td className="px-8 py-6 text-center">
                        <div className="flex justify-center">
                          <div className="flex items-center bg-zinc-900 border border-zinc-800 rounded-2xl overflow-hidden p-1 gap-1 shadow-inner focus-within:border-white/30 transition-all">
                            <button onClick={() => handleAdjustSaldo(u, Math.max(0, (wallet.balance || 0) - 1))} className="w-8 h-8 flex items-center justify-center text-zinc-600 hover:text-rose-500 rounded-xl"><i className="fa-solid fa-minus text-[10px]"></i></button>
                            <div className="min-w-[60px] text-center">
                               <input type="number" className="w-16 bg-transparent text-center text-lg font-black text-white italic leading-none outline-none" value={wallet.balance || 0} onChange={(e) => handleAdjustSaldo(u, parseInt(e.target.value) || 0)} />
                              <p className="text-[7px] text-zinc-600 font-black uppercase mt-0.5">Pontos</p>
                            </div>
                            <button onClick={() => handleAdjustSaldo(u, (wallet.balance || 0) + 1)} className="w-8 h-8 flex items-center justify-center text-emerald-500 hover:bg-emerald-500/5 rounded-xl"><i className="fa-solid fa-plus text-[10px]"></i></button>
                          </div>
                        </div>
                      </td>
                      <td className="px-8 py-6 text-right">
                        <div className="flex items-center justify-end gap-2">
                          <button onClick={() => setUserToEdit(u)} className="w-10 h-10 rounded-xl bg-zinc-800 text-zinc-500 flex items-center justify-center hover:bg-yellow-500 hover:text-black transition-all"><i className="fa-solid fa-user-gear"></i></button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      ) : (
        <div className="space-y-6">
          <div className="flex justify-between items-center">
            <h2 className="text-xl font-black text-white italic uppercase tracking-tighter">Catálogo de Brindes</h2>
            <button onClick={() => { setItemToEdit(null); setIsAddingItem(true); }} className="bg-emerald-500 text-black px-6 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-emerald-400 transition-all flex items-center gap-2">
              <i className="fa-solid fa-plus"></i> Novo Item
            </button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {db.rewardItems.map((item: RewardItem) => (
              <div key={item.id} className="bg-zinc-900 border border-zinc-800 rounded-[2.5rem] p-6 space-y-4 hover:border-zinc-500 transition-all flex flex-col relative overflow-hidden group">
                 <div className="flex items-center gap-4">
                    <img src={item.imageUrl} className="w-16 h-16 rounded-2xl object-cover grayscale group-hover:grayscale-0 transition-all" />
                    <div className="flex-1 min-w-0">
                       <h4 className="text-sm font-black text-white italic uppercase truncate">{item.name}</h4>
                       <p className="text-[8px] font-bold text-zinc-500 uppercase tracking-widest">{item.category} • {item.cost} pts</p>
                    </div>
                    <button onClick={() => setItemToEdit(item)} className="text-zinc-500 hover:text-white transition-colors">
                      <i className="fa-solid fa-pen-to-square"></i>
                    </button>
                 </div>

                 <div className="pt-4 border-t border-zinc-800">
                    <div className="flex items-center justify-between">
                       <p className="text-[10px] font-black text-zinc-500 uppercase">Gestão de Estoque</p>
                       <span className={`text-[10px] font-black italic ${item.stock < 5 ? 'text-rose-500 animate-pulse' : 'text-emerald-500'}`}>
                          {item.stock} UN DISPONÍVEIS
                       </span>
                    </div>

                    <div className="mt-3 flex items-center bg-black border border-zinc-800 rounded-2xl p-1 gap-1">
                      <button onClick={() => handleUpdateItemStock(item.id, item.stock - 1)} className="w-10 h-10 flex items-center justify-center text-zinc-600 hover:text-rose-500 hover:bg-rose-500/5 rounded-xl transition-all"><i className="fa-solid fa-minus"></i></button>
                      <input 
                        type="number" 
                        className="flex-1 bg-transparent text-center text-xl font-black text-white italic outline-none" 
                        value={item.stock} 
                        onChange={(e) => handleUpdateItemStock(item.id, parseInt(e.target.value) || 0)} 
                      />
                      <button onClick={() => handleUpdateItemStock(item.id, item.stock + 1)} className="w-10 h-10 flex items-center justify-center text-emerald-500 hover:bg-emerald-500/5 rounded-xl transition-all"><i className="fa-solid fa-plus"></i></button>
                    </div>
                 </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* MODAL GESTÃO ITEM (NOVO OU EDITAR) */}
      {(itemToEdit || isAddingItem) && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-xl z-[110] flex items-center justify-center p-4 overflow-y-auto">
          <div className="w-full max-w-xl bg-zinc-900 border border-zinc-800 rounded-[3rem] p-10 shadow-2xl animate-in zoom-in duration-300">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-3xl font-black text-white italic uppercase tracking-tighter">{itemToEdit ? 'Editar Brinde' : 'Novo Brinde'}</h3>
              <button onClick={() => { setItemToEdit(null); setIsAddingItem(false); }} className="w-10 h-10 rounded-full bg-zinc-800 text-zinc-500 flex items-center justify-center hover:text-white transition-colors"><i className="fa-solid fa-xmark"></i></button>
            </div>

            <form onSubmit={handleSaveItem} className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-zinc-500 uppercase ml-1">Nome do Brinde</label>
                  <input name="name" defaultValue={itemToEdit?.name || ''} required className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl focus:border-yellow-500 outline-none font-bold" />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-zinc-500 uppercase ml-1">Categoria</label>
                  <input name="category" defaultValue={itemToEdit?.category || ''} required className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl focus:border-yellow-500 outline-none font-bold" />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-zinc-500 uppercase ml-1">Foto do Produto (Upload)</label>
                <div className="flex items-center gap-4">
                  <div className="w-24 h-24 rounded-2xl bg-black border border-zinc-800 overflow-hidden flex items-center justify-center">
                    {previewUrl ? (
                      <img src={previewUrl} className="w-full h-full object-cover" />
                    ) : (
                      <i className="fa-solid fa-camera text-zinc-700 text-2xl"></i>
                    )}
                  </div>
                  <label className="flex-1 cursor-pointer">
                    <div className="w-full p-6 bg-black border-2 border-dashed border-zinc-800 text-zinc-500 rounded-2xl hover:border-yellow-500 hover:text-white transition-all text-center">
                      <i className="fa-solid fa-cloud-arrow-up text-xl mb-2 block"></i>
                      <span className="text-[9px] font-black uppercase tracking-widest">Selecionar Foto Real</span>
                    </div>
                    <input type="file" accept="image/*" className="hidden" onChange={handleFileChange} />
                  </label>
                </div>
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-zinc-500 uppercase ml-1">Descrição Curta</label>
                <textarea name="description" defaultValue={itemToEdit?.description || ''} className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl focus:border-yellow-500 outline-none" rows={2}></textarea>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-zinc-500 uppercase ml-1">Custo (Pontos)</label>
                  <input type="number" name="cost" defaultValue={itemToEdit?.cost || 10} required className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl focus:border-yellow-500 outline-none font-black text-xl italic" />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-zinc-500 uppercase ml-1">Estoque Inicial</label>
                  <div className="flex items-center bg-black border border-zinc-800 rounded-2xl p-1 gap-1 h-[60px] focus-within:border-yellow-500">
                    <button type="button" onClick={() => setModalStock(Math.max(0, modalStock - 1))} className="w-10 h-10 flex items-center justify-center text-zinc-600 hover:text-rose-500 rounded-xl transition-all">
                      <i className="fa-solid fa-minus"></i>
                    </button>
                    <input 
                      type="number" 
                      className="flex-1 bg-transparent text-center text-2xl font-black text-white italic outline-none" 
                      value={modalStock} 
                      onChange={(e) => setModalStock(parseInt(e.target.value) || 0)}
                    />
                    <button type="button" onClick={() => setModalStock(modalStock + 1)} className="w-10 h-10 flex items-center justify-center text-emerald-500 hover:bg-emerald-500/5 rounded-xl transition-all">
                      <i className="fa-solid fa-plus"></i>
                    </button>
                  </div>
                </div>
              </div>

              <button 
                type="submit" 
                disabled={isUploading}
                className={`w-full py-5 rounded-[1.5rem] font-black text-xs uppercase tracking-widest transition-all shadow-lg flex items-center justify-center gap-3 ${isUploading ? 'bg-zinc-800 text-zinc-500' : 'bg-yellow-500 text-black hover:bg-yellow-400 shadow-yellow-500/20'}`}
              >
                {isUploading ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-cloud-arrow-up"></i>}
                {isUploading ? 'ENVIANDO FOTO...' : (itemToEdit ? 'SALVAR ALTERAÇÕES' : 'CADASTRAR BRINDE')}
              </button>
            </form>
          </div>
        </div>
      )}

      {/* MODAL DE GESTÃO DE USUÁRIO (PERMISSÕES E DADOS) */}
      {userToEdit && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-xl z-[100] flex items-center justify-center p-4 overflow-y-auto">
          <div className="w-full max-w-3xl bg-zinc-900 border border-zinc-800 rounded-[3rem] p-8 md:p-12 shadow-2xl animate-in zoom-in duration-300 my-auto">
            <div className="flex justify-between items-start mb-8">
              <div>
                <h3 className="text-3xl font-black text-white italic uppercase tracking-tighter leading-none">Gestão de Colaborador</h3>
                <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest mt-2">Alterações Administrativas e de Perfil.</p>
              </div>
              <button onClick={() => setUserToEdit(null)} className="w-10 h-10 rounded-full bg-zinc-800 text-zinc-400 hover:text-white flex items-center justify-center transition-colors"><i className="fa-solid fa-xmark"></i></button>
            </div>

            <div className="space-y-10">
              {/* DADOS CADASTRAIS */}
              <div className="space-y-6">
                <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1 italic">Dados Cadastrais do Colaborador</label>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <p className="text-[8px] font-black text-zinc-600 uppercase tracking-widest ml-2">Nome Completo</p>
                    <input 
                      type="text" 
                      className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl focus:border-yellow-500 outline-none font-bold italic uppercase tracking-tighter" 
                      value={editUserName} 
                      onChange={e => setEditUserName(e.target.value)} 
                    />
                  </div>
                  <div className="space-y-2">
                    <p className="text-[8px] font-black text-zinc-600 uppercase tracking-widest ml-2">ID Corporativo / Matrícula</p>
                    <input 
                      type="text" 
                      className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl focus:border-yellow-500 outline-none font-bold" 
                      value={editUserId} 
                      onChange={e => setEditUserId(e.target.value)} 
                    />
                  </div>
                  <div className="space-y-2 md:col-span-2">
                    <p className="text-[8px] font-black text-zinc-600 uppercase tracking-widest ml-2">Redefinir Senha de Acesso</p>
                    <div className="relative">
                      <input 
                        type="text" 
                        className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl focus:border-yellow-500 outline-none font-bold" 
                        value={editUserPassword} 
                        onChange={e => setEditUserPassword(e.target.value)} 
                        placeholder="••••"
                      />
                      <i className="fa-solid fa-key absolute right-5 top-1/2 -translate-y-1/2 text-zinc-700"></i>
                    </div>
                  </div>
                </div>
                <button 
                  onClick={handleUpdateUserData}
                  className="px-8 py-3 bg-zinc-800 text-white border border-zinc-700 rounded-xl font-black text-[9px] uppercase tracking-widest hover:bg-white hover:text-black transition-all"
                >
                  SALVAR DADOS CADASTRAIS
                </button>
              </div>

              {/* STATUS DE APROVAÇÃO */}
              {userToEdit.status === UserStatus.PENDING && (
                <div className="bg-yellow-500/10 border border-yellow-500/20 p-8 rounded-[2rem] flex flex-col md:flex-row items-center justify-between gap-6 shadow-[0_0_30px_rgba(234,179,8,0.05)]">
                  <div>
                    <h4 className="text-yellow-500 font-black uppercase italic tracking-tighter text-lg">Aprovação Pendente</h4>
                    <p className="text-[10px] text-zinc-400 font-bold uppercase tracking-widest">Colaborador aguardando liberação de acesso.</p>
                  </div>
                  <button onClick={() => approveUser(userToEdit)} className="w-full md:w-auto bg-yellow-500 text-black px-10 py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-yellow-400 transition-all shadow-lg">ATIVAR AGORA</button>
                </div>
              )}

              {/* PERFIS E CAPABILIDADES */}
              <div className="space-y-4">
                <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1 italic">Perfil de Acesso (Cargo)</label>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2">
                  {[
                    { cap: Capability.OPERADOR, label: 'Operador' },
                    { cap: Capability.SUPERVISOR_COORDENADOR, label: 'Supervisor' },
                    { cap: Capability.GERENTE_AREA, label: 'Gerente Área' },
                    { cap: Capability.GERENTE_FABRIL, label: 'Gerente Fabril' },
                    { cap: Capability.GENTE_GESTAO, label: 'Gente & Gestão' },
                  ].map(role => (
                    <button key={role.cap} onClick={() => toggleCapability(userToEdit, role.cap)} className={`px-4 py-4 rounded-2xl border font-black text-[9px] uppercase tracking-widest transition-all ${userToEdit.capabilities.includes(role.cap) ? 'bg-white text-black border-white' : 'bg-black text-zinc-600 border-zinc-800 hover:border-zinc-500'}`}>{role.label}</button>
                  ))}
                </div>
              </div>

              <div className="space-y-4">
                <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1 italic">Privilégios Adicionais</label>
                <button onClick={() => toggleCapability(userToEdit, Capability.ADMIN)} className={`w-full p-6 rounded-[2rem] border flex items-center gap-4 transition-all ${userToEdit.capabilities.includes(Capability.ADMIN) ? 'bg-yellow-500/10 border-yellow-500 text-yellow-500 shadow-lg' : 'bg-black text-zinc-600 border-zinc-800'}`}>
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${userToEdit.capabilities.includes(Capability.ADMIN) ? 'bg-yellow-500 text-black' : 'bg-zinc-900 text-zinc-700'}`}><i className="fa-solid fa-shield-halved"></i></div>
                  <div className="text-left">
                    <p className="font-black uppercase italic text-xs tracking-tighter">Administrador Master</p>
                    <p className="text-[8px] font-bold uppercase tracking-widest opacity-60">Acesso total à gestão econômica, usuários e estoque.</p>
                  </div>
                </button>
              </div>

              <div className="pt-8 border-t border-zinc-800 flex justify-end">
                 <button onClick={() => setUserToEdit(null)} className="px-12 py-4 bg-zinc-800 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-zinc-700 transition-all">Fechar Gestão</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Admin;

import React, { useState, useMemo, useEffect } from 'react';
import { User, UserStatus, Role, Capability, RewardItem, Wallet, CoinType, TransactionType } from '../types';
import { saveDB, addAuditLog, getDB } from '../store';
import { ToastType } from '../components/Toast';
import { supabase } from '../App';

interface AdminProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
  showToast: (msg: string, type: ToastType) => void;
}

const Admin: React.FC<AdminProps> = ({ user, db, onRefreshDB, showToast }) => {
  const [activeTab, setActiveTab] = useState<'USERS' | 'ITEMS'>('USERS');
  const [userToEdit, setUserToEdit] = useState<User | null>(null);
  const [isAddingUser, setIsAddingUser] = useState(false);
  const [itemToEdit, setItemToEdit] = useState<RewardItem | null>(null);
  const [isAddingItem, setIsAddingItem] = useState(false);

  // Estados para o modal de item
  const [modalStock, setModalStock] = useState(0);
  const [isUploading, setIsUploading] = useState(false);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string>('');

  // Estados para o modal de edição/criação de usuário
  const [editUserName, setEditUserName] = useState('');
  const [editUserId, setEditUserId] = useState('');
  const [editUserPassword, setEditUserPassword] = useState('');

  // Sincroniza o estoque do modal quando o item a editar muda
  useEffect(() => {
    if (itemToEdit) {
      setModalStock(itemToEdit.stock || 0);
      setPreviewUrl(itemToEdit.imageUrl || '');
    } else if (isAddingItem) {
      setModalStock(0);
      setPreviewUrl('');
    }
    setSelectedFile(null);
  }, [itemToEdit, isAddingItem]);

  // Sincroniza os dados do usuário no modal de edição
  useEffect(() => {
    if (userToEdit) {
      setEditUserName(userToEdit.name);
      setEditUserId(userToEdit.corporateId);
      setEditUserPassword(userToEdit.passwordHash);
    } else if (isAddingUser) {
      setEditUserName('');
      setEditUserId('');
      setEditUserPassword('');
    }
  }, [userToEdit, isAddingUser]);

  const economicData = useMemo(() => {
    const rewardItems = db.rewardItems || [];
    const wallets = db.wallets || [];
    const totalStockValue = rewardItems.reduce((acc: number, item: RewardItem) => acc + ((item.cost || 0) * (item.stock || 0)), 0);
    const personalPoints = wallets.reduce((acc: number, w: Wallet) => acc + (w.balance || 0), 0);
    const donationPoints = wallets.reduce((acc: number, w: Wallet) => {
      return acc + ((w.donatableGold || 0) * 3) + ((w.donatableSilver || 0) * 2) + ((w.donatableBronze || 0) * 1);
    }, 0);
    return { totalStockValue, totalDistributedPoints: personalPoints + donationPoints, balanceGap: totalStockValue - (personalPoints + donationPoints) };
  }, [db.rewardItems, db.wallets]);

  // --- GESTÃO DE USUÁRIOS ---
  const handleSaveUser = () => {
    if (!editUserName.trim() || !editUserId.trim() || !editUserPassword.trim()) {
      showToast('Preencha todos os campos obrigatórios.', 'warning');
      return;
    }

    const currentDb = getDB();

    // Verificação de duplicidade de ID
    const idExists = currentDb.users.some((u: User) => u.corporateId === editUserId && u.id !== userToEdit?.id);
    if (idExists) {
      showToast('Este ID Corporativo já pertence a outro colaborador.', 'error');
      return;
    }

    if (userToEdit) {
      // EDIÇÃO
      const userInDb = currentDb.users.find((u: User) => u.id === userToEdit.id);
      if (userInDb) {
        userInDb.name = editUserName;
        userInDb.corporateId = editUserId;
        userInDb.passwordHash = editUserPassword;
        showToast('Dados do colaborador atualizados!', 'success');
      }
    } else {
      // CRIAÇÃO
      const newUser: User = {
        id: Math.random().toString(36).substr(2, 9),
        corporateId: editUserId,
        name: editUserName,
        passwordHash: editUserPassword,
        status: UserStatus.ACTIVE, // Criado pelo admin já nasce ativo
        roles: [Role.USER],
        capabilities: [Capability.OPERADOR], // Cargo padrão inicial
        createdAt: new Date().toISOString()
      };
      currentDb.users.push(newUser);
      currentDb.wallets.push({ 
        userId: newUser.id, 
        balance: 0, 
        donatableGold: 0, 
        donatableSilver: 0, 
        donatableBronze: 0 
      });
      showToast(`${editUserName} cadastrado com sucesso!`, 'success');
    }

    saveDB(currentDb);
    onRefreshDB();
    setUserToEdit(null);
    setIsAddingUser(false);
  };

  const handleAdjustVerba = (targetUser: User, newValue: number) => {
    const currentDb = getDB();
    const wallet = currentDb.wallets.find((w: any) => w.userId === targetUser.id);
    if (!wallet) return;
    let weight = 1;
    let coinType = CoinType.BRONZE;
    if (targetUser.capabilities.includes(Capability.ADMIN) || targetUser.capabilities.includes(Capability.GERENTE_FABRIL)) { coinType = CoinType.GOLD; weight = 3; }
    else if (targetUser.capabilities.includes(Capability.GERENTE_AREA)) { coinType = CoinType.SILVER; weight = 2; }
    const currentVal = coinType === CoinType.GOLD ? (wallet.donatableGold || 0) : coinType === CoinType.SILVER ? (wallet.donatableSilver || 0) : (wallet.donatableBronze || 0);
    const delta = newValue - currentVal;
    if (delta > 0 && (delta * weight) > economicData.balanceGap) { showToast('Limite de emissão atingido!', 'error'); return; }
    if (coinType === CoinType.GOLD) wallet.donatableGold = Math.max(0, newValue);
    else if (coinType === CoinType.SILVER) wallet.donatableSilver = Math.max(0, newValue);
    else wallet.donatableBronze = Math.max(0, newValue);
    if (delta !== 0) {
      currentDb.transactions.unshift({ id: Math.random().toString(36).substr(2, 9), type: delta > 0 ? TransactionType.CREDIT : TransactionType.DEBIT, amount: Math.abs(delta * weight), coinType, fromUserId: 'SYSTEM', toUserId: targetUser.id, reason: 'Ajuste Admin Verba', category: 'Administração', createdAt: new Date().toISOString(), createdBy: user.id, isDonationVerba: true });
      saveDB(currentDb); onRefreshDB();
    }
  };

  const handleAdjustSaldo = (targetUser: User, newValue: number) => {
    const currentDb = getDB();
    const wallet = currentDb.wallets.find((w: any) => w.userId === targetUser.id);
    if (!wallet) return;
    const delta = newValue - (wallet.balance || 0);
    if (delta > 0 && delta > economicData.balanceGap) { showToast('Estoque insuficiente!', 'error'); return; }
    wallet.balance = Math.max(0, newValue);
    if (delta !== 0) {
      currentDb.transactions.unshift({ id: Math.random().toString(36).substr(2, 9), type: delta > 0 ? TransactionType.CREDIT : TransactionType.DEBIT, amount: Math.abs(delta), fromUserId: 'SYSTEM', toUserId: targetUser.id, reason: 'Correção de Saldo Admin', category: 'Administração', createdAt: new Date().toISOString(), createdBy: user.id });
      saveDB(currentDb); onRefreshDB();
    }
  };

  const approveUser = (u: User) => {
    const currentDb = getDB();
    const userInDb = currentDb.users.find((user: User) => user.id === u.id);
    if (userInDb) { userInDb.status = UserStatus.ACTIVE; saveDB(currentDb); onRefreshDB(); setUserToEdit({ ...userInDb }); showToast(`${u.name} ativado!`, 'success'); }
  };

  const toggleCapability = (u: User, cap: Capability) => {
    const currentDb = getDB();
    const userInDb = currentDb.users.find((user: User) => user.id === u.id);
    if (userInDb) {
      const jobRoles = [Capability.OPERADOR, Capability.SUPERVISOR_COORDENADOR, Capability.GERENTE_AREA, Capability.GERENTE_FABRIL, Capability.GENTE_GESTAO];
      if (jobRoles.includes(cap)) { userInDb.capabilities = userInDb.capabilities.filter(c => !jobRoles.includes(c)); userInDb.capabilities.push(cap); }
      else { if (userInDb.capabilities.includes(cap)) { userInDb.capabilities = userInDb.capabilities.filter(c => c !== cap); } else { userInDb.capabilities.push(cap); } }
      saveDB(currentDb); onRefreshDB(); 
      if (userToEdit) setUserToEdit({ ...userInDb });
    }
  };

  // --- GESTÃO DE ITENS / ESTOQUE ---
  const handleUpdateItemStock = (itemId: string, newStock: number) => {
    const currentDb = getDB();
    const item = currentDb.rewardItems.find(i => i.id === itemId);
    if (item) {
      item.stock = Math.max(0, newStock);
      saveDB(currentDb);
      onRefreshDB();
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedFile(file);
      const url = URL.createObjectURL(file);
      setPreviewUrl(url);
    }
  };

  const handleSaveItem = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsUploading(true);

    try {
      const formData = new FormData(e.currentTarget as HTMLFormElement);
      let finalImageUrl = itemToEdit?.imageUrl || '';

      if (selectedFile) {
        const fileExt = selectedFile.name.split('.').pop();
        const fileName = `${Math.random().toString(36).substr(2, 9)}.${fileExt}`;
        const filePath = `items/${fileName}`;
        const { error: uploadError } = await supabase.storage.from('reward-images').upload(filePath, selectedFile);
        if (uploadError) throw uploadError;
        const { data: { publicUrl } } = supabase.storage.from('reward-images').getPublicUrl(filePath);
        finalImageUrl = publicUrl;
      }

      const itemData = {
        name: formData.get('name') as string,
        description: formData.get('description') as string,
        imageUrl: finalImageUrl,
        cost: Number(formData.get('cost')),
        stock: modalStock,
        category: formData.get('category') as string,
        isActive: true,
      };

      const currentDb = getDB();
      if (itemToEdit) {
        const idx = currentDb.rewardItems.findIndex(i => i.id === itemToEdit.id);
        currentDb.rewardItems[idx] = { ...itemToEdit, ...itemData };
        showToast('Item atualizado com sucesso!', 'success');
      } else {
        currentDb.rewardItems.push({ ...itemData, id: Math.random().toString(36).substr(2, 9) });
        showToast('Novo item adicionado ao catálogo!', 'success');
      }

      saveDB(currentDb);
      onRefreshDB();
      setItemToEdit(null);
      setIsAddingItem(false);
    } catch (err: any) {
      console.error(err);
      showToast('Erro ao salvar item: ' + err.message, 'error');
    } finally {
      setIsUploading(false);
    }
  };

  const sortedUsers = [...(db.users || [])].sort((a, b) => (a.status === UserStatus.PENDING ? -1 : 1));

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter leading-none">Painel de Controle</h1>
          <p className="text-zinc-500 text-[10px] font-black uppercase tracking-[0.2em] mt-2 italic">Gestão Econômica e Inventário de Brindes.</p>
        </div>
        <div className="flex gap-2 bg-zinc-900/50 p-2 rounded-2xl w-fit border border-zinc-800">
          <button onClick={() => setActiveTab('USERS')} className={`px-8 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeTab === 'USERS' ? 'bg-yellow-500 text-black shadow-lg shadow-yellow-500/10' : 'text-zinc-500 hover:text-white'}`}>Colaboradores</button>
          <button onClick={() => setActiveTab('ITEMS')} className={`px-8 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${activeTab === 'ITEMS' ? 'bg-white text-black shadow-lg shadow-white/10' : 'text-zinc-500 hover:text-white'}`}>Gerenciar Estoque</button>
        </div>
      </header>

      {/* CARDS ECONÔMICOS */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className={`p-6 rounded-[2rem] border transition-colors ${economicData.balanceGap < 0 ? 'bg-rose-500/10 border-rose-500/20' : 'bg-emerald-500/10 border-emerald-500/20'}`}>
          <p className="text-[9px] font-black text-zinc-500 uppercase tracking-widest mb-1">Capacidade de Emissão (Estoque Livre)</p>
          <div className="flex items-baseline gap-2">
            <span className={`text-4xl font-black italic tracking-tighter ${economicData.balanceGap < 0 ? 'text-rose-500' : 'text-emerald-500'}`}>{economicData.balanceGap || 0}</span>
            <span className="text-[8px] font-black text-zinc-600 uppercase">Pts</span>
          </div>
        </div>
        <div className="p-6 rounded-[2rem] bg-zinc-900 border border-zinc-800">
          <p className="text-[9px] font-black text-zinc-500 uppercase tracking-widest mb-1">Passivo (Moedas em Mãos)</p>
          <div className="flex items-baseline gap-2 text-white">
            <span className="text-4xl font-black italic tracking-tighter">{economicData.totalDistributedPoints || 0}</span>
            <span className="text-[8px] font-black text-zinc-600 uppercase">Pts</span>
          </div>
        </div>
        <div className="p-6 rounded-[2rem] bg-zinc-900 border border-zinc-800">
          <p className="text-[9px] font-black text-zinc-500 uppercase tracking-widest mb-1">Patrimônio Brindes (Total em Itens)</p>
          <div className="flex items-baseline gap-2 text-yellow-500">
            <span className="text-4xl font-black italic tracking-tighter">{economicData.totalStockValue || 0}</span>
            <span className="text-[8px] font-black text-zinc-600 uppercase">Pts</span>
          </div>
        </div>
      </div>

      {activeTab === 'USERS' ? (
        <div className="bg-zinc-900/40 border border-zinc-800 rounded-[3rem] overflow-hidden">
          <div className="p-8 border-b border-zinc-800 flex justify-between items-center bg-black/20 text-white">
            <h2 className="font-black italic uppercase tracking-tighter text-xl text-white">Lista de Colaboradores</h2>
            <button 
              onClick={() => setIsAddingUser(true)}
              className="bg-emerald-500 text-black px-6 py-2.5 rounded-xl font-black text-[9px] uppercase tracking-widest hover:bg-emerald-400 transition-all flex items-center gap-2 shadow-lg shadow-emerald-500/10"
            >
              <i className="fa-solid fa-user-plus"></i> Novo Colaborador
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-black/40">
                <tr>
                  <th className="px-8 py-5 text-[9px] font-black text-zinc-600 uppercase tracking-[0.2em]">Colaborador</th>
                  <th className="px-8 py-5 text-[9px] font-black text-zinc-600 uppercase tracking-[0.2em] text-center">Verba Liderança</th>
                  <th className="px-8 py-5 text-[9px] font-black text-zinc-600 uppercase tracking-[0.2em] text-center">Saldo Loja</th>
                  <th className="px-8 py-5 text-[9px] font-black text-zinc-600 uppercase tracking-[0.2em] text-right">Ações</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-zinc-800">
                {sortedUsers.map((u: User) => {
                  const wallet = db.wallets.find((w: any) => w.userId === u.id) || { balance: 0, donatableGold: 0, donatableSilver: 0, donatableBronze: 0 };
                  const isLeader = u.capabilities.some(c => [Capability.SUPERVISOR_COORDENADOR, Capability.GERENTE_AREA, Capability.GERENTE_FABRIL, Capability.GENTE_GESTAO, Capability.ADMIN].includes(c));
                  const coinValue = u.capabilities.includes(Capability.ADMIN) || u.capabilities.includes(Capability.GERENTE_FABRIL) ? (wallet.donatableGold || 0) : u.capabilities.includes(Capability.GERENTE_AREA) ? (wallet.donatableSilver || 0) : (wallet.donatableBronze || 0);
                  return (
                    <tr key={u.id} className="hover:bg-white/[0.02] transition-colors">
                      <td className="px-8 py-6">
                        <p className="font-black text-white uppercase italic tracking-tighter leading-none mb-1">{u.name}</p>
                        <div className="flex items-center gap-2">
                          <span className="text-[9px] text-zinc-600 font-bold uppercase tracking-widest">{u.corporateId}</span>
                          {u.status === UserStatus.PENDING && <span className="text-[7px] bg-yellow-500 text-black px-1.5 py-0.5 rounded font-black uppercase">Aprovação Pendente</span>}
                        </div>
                      </td>
                      <td className="px-8 py-6 text-center">
                        <div className="flex justify-center">
                          {isLeader ? (
                            <div className="flex items-center bg-black border border-zinc-800 rounded-2xl overflow-hidden p-1 gap-1 shadow-inner focus-within:border-yellow-500/50 transition-all">
                              <button onClick={() => handleAdjustVerba(u, Math.max(0, coinValue - 1))} className="w-8 h-8 flex items-center justify-center text-zinc-600 hover:text-white hover:bg-zinc-800 rounded-xl"><i className="fa-solid fa-minus text-[10px]"></i></button>
                              <div className="min-w-[50px] text-center">
                                <input type="number" className="w-12 bg-transparent text-center text-lg font-black text-yellow-500 italic leading-none outline-none" value={coinValue} onChange={(e) => handleAdjustVerba(u, parseInt(e.target.value) || 0)} />
                                <p className="text-[7px] text-zinc-600 font-black uppercase mt-0.5">Moedas</p>
                              </div>
                              <button onClick={() => handleAdjustVerba(u, coinValue + 1)} className="w-8 h-8 flex items-center justify-center text-yellow-500 hover:bg-yellow-500/10 rounded-xl"><i className="fa-solid fa-plus text-[10px]"></i></button>
                            </div>
                          ) : <span className="text-[9px] text-zinc-700 font-black uppercase italic">Sem Perfil Líder</span>}
                        </div>
                      </td>
                      <td className="px-8 py-6 text-center">
                        <div className="flex justify-center">
                          <div className="flex items-center bg-zinc-900 border border-zinc-800 rounded-2xl overflow-hidden p-1 gap-1 shadow-inner focus-within:border-white/30 transition-all">
                            <button onClick={() => handleAdjustSaldo(u, Math.max(0, (wallet.balance || 0) - 1))} className="w-8 h-8 flex items-center justify-center text-zinc-600 hover:text-rose-500 rounded-xl"><i className="fa-solid fa-minus text-[10px]"></i></button>
                            <div className="min-w-[60px] text-center">
                               <input type="number" className="w-16 bg-transparent text-center text-lg font-black text-white italic leading-none outline-none" value={wallet.balance || 0} onChange={(e) => handleAdjustSaldo(u, parseInt(e.target.value) || 0)} />
                              <p className="text-[7px] text-zinc-600 font-black uppercase mt-0.5">Pontos</p>
                            </div>
                            <button onClick={() => handleAdjustSaldo(u, (wallet.balance || 0) + 1)} className="w-8 h-8 flex items-center justify-center text-emerald-500 hover:bg-emerald-500/5 rounded-xl"><i className="fa-solid fa-plus text-[10px]"></i></button>
                          </div>
                        </div>
                      </td>
                      <td className="px-8 py-6 text-right">
                        <div className="flex items-center justify-end gap-2">
                          <button onClick={() => setUserToEdit(u)} className="w-10 h-10 rounded-xl bg-zinc-800 text-zinc-500 flex items-center justify-center hover:bg-yellow-500 hover:text-black transition-all"><i className="fa-solid fa-user-gear"></i></button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      ) : (
        <div className="space-y-6">
          <div className="flex justify-between items-center">
            <h2 className="text-xl font-black text-white italic uppercase tracking-tighter">Catálogo de Brindes</h2>
            <button onClick={() => { setItemToEdit(null); setIsAddingItem(true); }} className="bg-emerald-500 text-black px-6 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-emerald-400 transition-all flex items-center gap-2">
              <i className="fa-solid fa-plus"></i> Novo Item
            </button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {db.rewardItems.map((item: RewardItem) => (
              <div key={item.id} className="bg-zinc-900 border border-zinc-800 rounded-[2.5rem] p-6 space-y-4 hover:border-zinc-500 transition-all flex flex-col relative overflow-hidden group">
                 <div className="flex items-center gap-4">
                    <img src={item.imageUrl} className="w-16 h-16 rounded-2xl object-cover grayscale group-hover:grayscale-0 transition-all" />
                    <div className="flex-1 min-w-0">
                       <h4 className="text-sm font-black text-white italic uppercase truncate">{item.name}</h4>
                       <p className="text-[8px] font-bold text-zinc-500 uppercase tracking-widest">{item.category} • {item.cost} pts</p>
                    </div>
                    <button onClick={() => setItemToEdit(item)} className="text-zinc-500 hover:text-white transition-colors">
                      <i className="fa-solid fa-pen-to-square"></i>
                    </button>
                 </div>

                 <div className="pt-4 border-t border-zinc-800">
                    <div className="flex items-center justify-between">
                       <p className="text-[10px] font-black text-zinc-500 uppercase">Gestão de Estoque</p>
                       <span className={`text-[10px] font-black italic ${item.stock < 5 ? 'text-rose-500 animate-pulse' : 'text-emerald-500'}`}>
                          {item.stock} UN DISPONÍVEIS
                       </span>
                    </div>

                    <div className="mt-3 flex items-center bg-black border border-zinc-800 rounded-2xl p-1 gap-1">
                      <button onClick={() => handleUpdateItemStock(item.id, item.stock - 1)} className="w-10 h-10 flex items-center justify-center text-zinc-600 hover:text-rose-500 hover:bg-rose-500/5 rounded-xl transition-all"><i className="fa-solid fa-minus"></i></button>
                      <input 
                        type="number" 
                        className="flex-1 bg-transparent text-center text-xl font-black text-white italic outline-none" 
                        value={item.stock} 
                        onChange={(e) => handleUpdateItemStock(item.id, parseInt(e.target.value) || 0)} 
                      />
                      <button onClick={() => handleUpdateItemStock(item.id, item.stock + 1)} className="w-10 h-10 flex items-center justify-center text-emerald-500 hover:bg-emerald-500/5 rounded-xl transition-all"><i className="fa-solid fa-plus"></i></button>
                    </div>
                 </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* MODAL GESTÃO ITEM (NOVO OU EDITAR) */}
      {(itemToEdit || isAddingItem) && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-xl z-[110] flex items-center justify-center p-4 overflow-y-auto">
          <div className="w-full max-w-xl bg-zinc-900 border border-zinc-800 rounded-[3rem] p-10 shadow-2xl animate-in zoom-in duration-300">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-3xl font-black text-white italic uppercase tracking-tighter">{itemToEdit ? 'Editar Brinde' : 'Novo Brinde'}</h3>
              <button onClick={() => { setItemToEdit(null); setIsAddingItem(false); }} className="w-10 h-10 rounded-full bg-zinc-800 text-zinc-500 flex items-center justify-center hover:text-white transition-colors"><i className="fa-solid fa-xmark"></i></button>
            </div>

            <form onSubmit={handleSaveItem} className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-zinc-500 uppercase ml-1">Nome do Brinde</label>
                  <input name="name" defaultValue={itemToEdit?.name || ''} required className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl focus:border-yellow-500 outline-none font-bold" />
                </div>
                <div className="space-y-1">
