import React, { useState, useMemo } from 'react';
import { User, TransactionType, Transaction, Capability, CoinType, Wallet, PilarType } from '../types';
import { saveDB, addAuditLog, getDB } from '../store';
import { ToastType } from '../components/Toast';

interface LeadershipProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
  showToast: (msg: string, type: ToastType) => void;
}

const PILARES: PilarType[] = [
  'Segurança', 'Qualidade', 'Manutenção', 'Financeiro', 
  'Logística', 'Meio Ambiente', 'Gestão', 'Gente'
];

const Leadership: React.FC<LeadershipProps> = ({ user, db, onRefreshDB, showToast }) => {
  const [recipientId, setRecipientId] = useState('');
  const [pillar, setPillar] = useState<PilarType | ''>('');
  const [amount, setAmount] = useState<string>('1');
  const [reason, setReason] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const wallet = useMemo(() => {
    return db.wallets.find((w: Wallet) => w.userId === user.id) || { donatableGold: 0, donatableSilver: 0, donatableBronze: 0 };
  }, [user.id, db.wallets]);

  const coinConfig = useMemo(() => {
    if (user.capabilities.includes(Capability.ADMIN) || user.capabilities.includes(Capability.GERENTE_FABRIL)) {
      return { type: CoinType.GOLD, weight: 3, label: 'Moeda de Ouro', color: 'text-yellow-500', stock: wallet.donatableGold || 0 };
    }
    if (user.capabilities.includes(Capability.GERENTE_AREA)) {
      return { type: CoinType.SILVER, weight: 2, label: 'Moeda de Prata', color: 'text-zinc-400', stock: wallet.donatableSilver || 0 };
    }
    return { type: CoinType.BRONZE, weight: 1, label: 'Moeda de Bronze', color: 'text-orange-600', stock: wallet.donatableBronze || 0 };
  }, [user.capabilities, wallet]);

  const activeUsers = db.users.filter((u: User) => u.status === 'ACTIVE' && u.id !== user.id);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isSubmitting) return;

    const numCoins = Number(amount);
    if (numCoins > coinConfig.stock) {
      showToast(`Você não possui verba suficiente. Saldo disponível: ${coinConfig.stock} moedas.`, 'error');
      return;
    }

    if (!recipientId || !pillar || numCoins <= 0 || !reason.trim()) {
      showToast('Preencha todos os campos corretamente.', 'warning');
      return;
    }

    try {
      setIsSubmitting(true);
      const currentDb = getDB(); 
      const totalPoints = numCoins * coinConfig.weight;

      // 1. Debita da VERBA do doador
      const donorWallet = currentDb.wallets.find((w: any) => w.userId === user.id);
      if (coinConfig.type === CoinType.GOLD) donorWallet.donatableGold -= numCoins;
      if (coinConfig.type === CoinType.SILVER) donorWallet.donatableSilver -= numCoins;
      if (coinConfig.type === CoinType.BRONZE) donorWallet.donatableBronze -= numCoins;

      // 2. Credita no SALDO PESSOAL do receptor
      let recipientWallet = currentDb.wallets.find((w: any) => w.userId === recipientId);
      if (!recipientWallet) {
        currentDb.wallets.push({ userId: recipientId, balance: 0, donatableGold: 0, donatableSilver: 0, donatableBronze: 0 });
        recipientWallet = currentDb.wallets[currentDb.wallets.length - 1];
      }
      recipientWallet.balance += totalPoints;

      const tx: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        type: TransactionType.CREDIT,
        amount: totalPoints,
        coinType: coinConfig.type,
        pillar: pillar as PilarType,
        fromUserId: user.id,
        toUserId: recipientId,
        reason: reason.trim(),
        category: `Reconhecimento: ${pillar}`,
        createdAt: new Date().toISOString(),
        createdBy: user.id
      };
      currentDb.transactions.unshift(tx);

      saveDB(currentDb);
      onRefreshDB();
      showToast(`Sucesso! ${numCoins} moedas enviadas.`, 'success');
      setAmount('1'); setReason(''); setRecipientId(''); setPillar('');
    } catch (error) {
      showToast('Erro ao processar envio.', 'error');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto space-y-8 animate-in fade-in duration-500 pb-10">
      <header className="flex justify-between items-end">
        <div>
          <p className={`font-black text-[10px] uppercase tracking-[0.3em] mb-1 italic ${coinConfig.color}`}>Sua Verba Disponível: {coinConfig.stock} {coinConfig.label}s</p>
          <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter">Enviar Reconhecimento</h1>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-5 gap-8">
        <div className="lg:col-span-3">
          <form onSubmit={handleSubmit} className="bg-zinc-900/40 p-8 rounded-[2.5rem] border border-zinc-800 space-y-6 shadow-2xl relative">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Colaborador</label>
                <select required className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl appearance-none outline-none font-bold" value={recipientId} onChange={e => setRecipientId(e.target.value)}>
                  <option value="">Selecione...</option>
                  {activeUsers.map((u: User) => (<option key={u.id} value={u.id}>{u.name.toUpperCase()}</option>))}
                </select>
              </div>
              <div className="space-y-2">
                <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Pilar do Reconhecimento</label>
                <select required className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl appearance-none outline-none font-bold" value={pillar} onChange={e => setPillar(e.target.value as PilarType)}>
                  <option value="">Selecione o Pilar...</option>
                  {PILARES.map(p => (<option key={p} value={p}>{p}</option>))}
                </select>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Qtd de Moedas</label>
                <input type="number" required min="1" max={coinConfig.stock} className={`w-full p-4 bg-black border border-zinc-800 font-black rounded-2xl text-2xl outline-none ${coinConfig.color}`} value={amount} onChange={e => setAmount(e.target.value)} />
              </div>
              <div className="flex flex-col justify-center p-4 bg-black/40 rounded-2xl border border-zinc-800">
                 <p className="text-[10px] font-black text-zinc-500 uppercase">Impacto na Loja:</p>
                 <p className="text-3xl font-black text-white italic tracking-tighter">+{Number(amount) * coinConfig.weight} Pts</p>
              </div>
            </div>
            <div className="space-y-2">
              <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Motivo</label>
              <textarea required rows={4} className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl outline-none" placeholder="Por que este colaborador merece?" value={reason} onChange={e => setReason(e.target.value)}></textarea>
            </div>
            <button type="submit" disabled={isSubmitting || coinConfig.stock === 0} className={`w-full py-5 rounded-2xl font-black text-lg uppercase tracking-widest transition-all ${isSubmitting || coinConfig.stock === 0 ? 'bg-zinc-800 text-zinc-500' : 'bg-yellow-500 text-black hover:bg-yellow-400'}`}>
              {coinConfig.stock === 0 ? 'SEM VERBA DISPONÍVEL' : 'CONFIRMAR RECONHECIMENTO'}
            </button>
          </form>
        </div>
        <div className="lg:col-span-2 space-y-4">
           <div className="p-8 rounded-[2.5rem] bg-zinc-900 border border-zinc-800">
              <h4 className="font-black text-white uppercase italic text-xl mb-4 tracking-tighter">Como funciona?</h4>
              <p className="text-xs text-zinc-400 font-medium leading-relaxed">
                Você recebeu esta verba do administrador. Quando você doa moedas, elas são convertidas em <strong>Pontos de Compra</strong> para o colaborador, permitindo que ele resgate brindes na loja.
                <br/><br/>
                O reconhecimento deve estar associado a um dos <strong>8 Pilares Estratégicos</strong> da nossa unidade.
              </p>
           </div>
        </div>
      </div>
    </div>
  );
};

export default Leadership;

import React, { useMemo } from 'react';
import { User, Transaction, TransactionType, Capability, Wallet, CoinType, PilarType } from '../types';

interface DashboardProps { user: User; db: any; setView: (v: any) => void; }

const PILARES: PilarType[] = [
  'Segurança', 'Qualidade', 'Manutenção', 'Financeiro', 
  'Logística', 'Meio Ambiente', 'Gestão', 'Gente'
];

const Dashboard: React.FC<DashboardProps> = ({ user, db, setView }) => {
  const wallet: Wallet = db.wallets.find((w: any) => w.userId === user.id) || { 
    balance: 0, 
    donatableGold: 0, 
    donatableSilver: 0, 
    donatableBronze: 0 
  };

  const isLeader = user.capabilities.some(c => [
    Capability.SUPERVISOR_COORDENADOR, 
    Capability.GERENTE_AREA, 
    Capability.GERENTE_FABRIL, 
    Capability.GENTE_GESTAO,
    Capability.ADMIN
  ].includes(c));

  // Matriz Pilar x Moeda
  const pilarStats = useMemo(() => {
    const stats: Record<string, Record<CoinType, number>> = {};
    PILARES.forEach(p => {
      stats[p] = { [CoinType.BRONZE]: 0, [CoinType.SILVER]: 0, [CoinType.GOLD]: 0 };
    });

    (db.transactions || []).forEach((t: Transaction) => {
      if (t.toUserId === user.id && t.type === TransactionType.CREDIT && t.pillar && t.coinType) {
        if (!stats[t.pillar]) stats[t.pillar] = { [CoinType.BRONZE]: 0, [CoinType.SILVER]: 0, [CoinType.GOLD]: 0 };
        stats[t.pillar][t.coinType]++;
      }
    });

    return stats;
  }, [db.transactions, user.id]);

  const totalDonatablePoints = useMemo(() => {
    const gold = (wallet.donatableGold || 0) * 3;
    const silver = (wallet.donatableSilver || 0) * 2;
    const bronze = (wallet.donatableBronze || 0) * 1;
    return gold + silver + bronze;
  }, [wallet]);

  const userTransactions = (db.transactions || [])
    .filter((t: Transaction) => t.toUserId === user.id || t.fromUserId === user.id)
    .sort((a: Transaction, b: Transaction) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
    .slice(0, 5);

  const pendingOrders = (db.orders || []).filter((o: any) => o.userId === user.id && o.status === 'PENDING').length;

  const totalGanhos = useMemo(() => {
    return (db.transactions || [])
      .filter((t: Transaction) => t.toUserId === user.id && t.type === TransactionType.CREDIT && !t.isDonationVerba)
      .reduce((acc: number, t: Transaction) => acc + (t.amount || 0), 0);
  }, [db.transactions, user.id]);

  const totalMoedasRecebidas = useMemo(() => {
    return (db.transactions || [])
      .filter((t: Transaction) => t.toUserId === user.id && t.type === TransactionType.CREDIT && !t.isDonationVerba && t.coinType)
      .length;
  }, [db.transactions, user.id]);

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-12">
      <header className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div className="flex items-center gap-6">
          <div className="relative w-24 h-24 flex items-center justify-center">
            <div className="absolute inset-0 bg-yellow-500" style={{ clipPath: 'polygon(50% 0%, 55% 2%, 60% 0%, 65% 5%, 72% 3%, 76% 9%, 84% 9%, 87% 16%, 93% 19%, 93% 27%, 99% 32%, 97% 40%, 100% 50%, 97% 60%, 99% 68%, 93% 73%, 93% 81%, 87% 84%, 84% 91%, 76% 91%, 72% 97%, 65% 95%, 60% 100%, 55% 98%, 50% 100%, 45% 98%, 40% 100%, 35% 95%, 28% 97%, 24% 91%, 16% 91%, 13% 84%, 7% 81%, 7% 73%, 1% 68%, 3% 60%, 0% 50%, 3% 40%, 1% 32%, 7% 27%, 7% 19%, 13% 16%, 16% 9%, 24% 9%, 28% 3%, 35% 5%, 40% 0%, 45% 2%)' }}></div>
            <div className="absolute w-[88%] h-[88%] bg-black rounded-full z-10 flex flex-col items-center justify-center">
              <span className="text-yellow-500 font-black italic text-[14px] leading-none">SUPPLY</span>
              <div className="w-10 h-[1px] bg-white my-1"></div>
              <span className="text-white font-bold text-[6px] uppercase whitespace-nowrap">Nada nos para!</span>
            </div>
          </div>
          <div>
            <p className="text-white font-black uppercase tracking-[0.3em] text-[10px] mb-1 opacity-50 italic">Nada nos para!</p>
            <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter">Fala, {user.name.split(' ')[0]}!</h1>
          </div>
        </div>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-gradient-to-br from-yellow-500 to-yellow-600 p-8 rounded-[3rem] shadow-xl relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-4 opacity-10 text-8xl">
            <i className="fa-solid fa-cart-shopping animate-pulse text-black"></i>
          </div>
          <p className="text-black font-black uppercase tracking-widest text-[10px] mb-1">Saldo para Compras</p>
          <div className="flex items-center gap-3">
            <span className="text-6xl font-black text-black leading-none tracking-tighter">{wallet.balance || 0}</span>
            <div className="w-10 h-10 rounded-full border-2 border-black/20 flex items-center justify-center">
              <i className="fa-solid fa-gift text-black"></i>
            </div>
          </div>
          <button onClick={() => setView('STORE')} className="mt-6 flex items-center gap-2 bg-black text-yellow-500 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:gap-4 transition-all">Acessar Loja <i className="fa-solid fa-arrow-right"></i></button>
        </div>

        {isLeader && (
          <div className="bg-zinc-900 border border-zinc-800 p-8 rounded-[3rem] flex flex-col justify-center relative group overflow-hidden">
             <div className="absolute top-0 right-0 p-4 opacity-5 text-6xl group-hover:scale-110 transition-transform">
                <i className="fa-solid fa-hand-holding-dollar text-white"></i>
             </div>
             <p className="text-zinc-500 font-black uppercase tracking-widest text-[10px] mb-2">Verba para Doação</p>
             <div className="flex items-center gap-4">
                <span className="text-4xl font-black text-emerald-500 italic tracking-tighter">{totalDonatablePoints}</span>
                <div className="flex flex-col">
                  <span className="text-[8px] font-black text-zinc-600 uppercase">Pontos p/</span>
                  <span className="text-[8px] font-black text-zinc-600 uppercase leading-none">Distribuir</span>
                </div>
             </div>
             <button onClick={() => setView('LEADERSHIP')} className="mt-4 text-emerald-500 font-black uppercase text-[9px] tracking-widest flex items-center gap-2 hover:gap-3 transition-all">
               Distribuir Agora <i className="fa-solid fa-bolt"></i>
             </button>
          </div>
        )}

        <div className="bg-zinc-900 border border-zinc-800 p-8 rounded-[3rem] flex flex-col justify-center">
          <p className="text-zinc-500 font-black uppercase tracking-widest text-[10px] mb-2">Pedidos Pendentes</p>
          <div className="flex items-center gap-4">
            <span className="text-4xl font-black text-white italic">{pendingOrders}</span>
            <div className="px-3 py-1 bg-yellow-500/10 text-yellow-500 rounded-lg text-[9px] font-black uppercase tracking-wider border border-yellow-500/20">Status</div>
          </div>
        </div>

        <div className="bg-zinc-900 border border-zinc-800 p-8 rounded-[3rem] flex flex-col justify-center">
          <p className="text-zinc-500 font-black uppercase tracking-widest text-[10px] mb-2">Total de Moedas</p>
          <div className="flex items-center gap-4">
            <span className="text-4xl font-black text-white italic tracking-tighter">{totalMoedasRecebidas}</span>
            <div className="w-8 h-8 rounded-full border border-yellow-500/30 flex items-center justify-center">
              <i className="fa-solid fa-crown text-yellow-500 text-sm"></i>
            </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <section className="lg:col-span-2 space-y-4">
          <h3 className="text-xs font-black text-white uppercase tracking-[0.3em] italic px-2">Timeline de Atividades</h3>
          <div className="bg-zinc-900 rounded-[3rem] border border-zinc-800 overflow-hidden">
            <table className="w-full">
              <tbody className="divide-y divide-zinc-800">
                {userTransactions.length > 0 ? userTransactions.map((t: Transaction) => (
                  <tr key={t.id} className="hover:bg-black/40 transition-colors">
                    <td className="px-8 py-6">
                      <div className={`w-10 h-10 rounded-full border flex items-center justify-center ${t.isDonationVerba ? 'border-emerald-500/30 bg-emerald-500/5 text-emerald-500' : t.type === TransactionType.CREDIT ? 'border-yellow-500/30 bg-yellow-500/5 text-yellow-500' : 'border-zinc-700 bg-zinc-800 text-zinc-500'}`}>
                        <i className={`fa-solid ${t.isDonationVerba ? 'fa-bolt' : t.type === TransactionType.CREDIT ? 'fa-plus' : 'fa-minus'} text-xs`}></i>
                      </div>
                    </td>
                    <td className="px-6 py-6">
                      <p className="text-xs font-black text-white uppercase tracking-tight leading-none mb-1">{t.reason}</p>
                      <p className="text-[9px] text-zinc-500 font-black uppercase tracking-widest">{t.category}</p>
                    </td>
                    <td className="px-8 py-6 text-right">
                      <p className={`text-xl font-black italic tracking-tighter ${t.isDonationVerba ? 'text-emerald-500' : t.type === TransactionType.CREDIT ? 'text-yellow-500' : 'text-zinc-500'}`}>
                        {t.type === TransactionType.CREDIT ? '+' : '-'}{t.amount || 0}
                      </p>
                      <p className="text-[9px] text-zinc-600 font-bold">{new Date(t.createdAt).toLocaleDateString()}</p>
                    </td>
                  </tr>
                )) : (<tr><td className="p-12 text-center text-zinc-600 font-black uppercase text-[10px] tracking-widest italic">Sem atividades.</td></tr>)}
              </tbody>
            </table>
          </div>
        </section>

        <section className="space-y-4">
          <h3 className="text-xs font-black text-white uppercase tracking-[0.3em] italic px-2">Seu Desempenho por Pilar</h3>
          <div className="bg-zinc-900/60 border border-zinc-800 rounded-[3rem] p-6 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="border-b border-zinc-800">
                    <th className="py-3 text-[9px] font-black text-zinc-600 uppercase tracking-widest">Pilar</th>
                    <th className="py-3 px-2 text-center text-orange-600"><i className="fa-solid fa-circle-dot"></i></th>
                    <th className="py-3 px-2 text-center text-zinc-400"><i className="fa-solid fa-circle-dot"></i></th>
                    <th className="py-3 px-2 text-center text-yellow-500"><i className="fa-solid fa-circle-dot"></i></th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-zinc-800/50">
                  {PILARES.map(p => (
                    <tr key={p} className="hover:bg-white/[0.02] transition-colors">
                      <td className="py-3 text-[10px] font-black text-white uppercase italic">{p}</td>
                      <td className="py-3 px-2 text-center text-xs font-black text-orange-600/60">{pilarStats[p][CoinType.BRONZE] || '-'}</td>
                      <td className="py-3 px-2 text-center text-xs font-black text-zinc-400/60">{pilarStats[p][CoinType.SILVER] || '-'}</td>
                      <td className="py-3 px-2 text-center text-xs font-black text-yellow-500">{pilarStats[p][CoinType.GOLD] || '-'}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <div className="mt-6 pt-4 border-t border-zinc-800 flex justify-between items-center px-2">
               <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest italic">Total de Moedas:</span>
               <span className="text-2xl font-black text-white italic tracking-tighter">{totalMoedasRecebidas}</span>
            </div>
          </div>
        </section>
      </div>
    </div>
  );
};
export default Dashboard;

import React, { useState, useMemo, useEffect } from 'react';
import { User, UserStatus, Role, Capability, RewardItem, Wallet, CoinType, TransactionType, Transaction } from '../types';
import { saveDB, addAuditLog, getDB } from '../store';
import { ToastType } from '../components/Toast';
import { supabase } from '../App';

interface AdminProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
  showToast: (msg: string, type: ToastType) => void;
}

const Admin: React.FC<AdminProps> = ({ user, db, onRefreshDB, showToast }) => {
  const [activeTab, setActiveTab] = useState<'USERS' | 'ITEMS' | 'STATS'>('USERS');
  const [userToEdit, setUserToEdit] = useState<User | null>(null);
  const [isAddingUser, setIsAddingUser] = useState(false);
  const [itemToEdit, setItemToEdit] = useState<RewardItem | null>(null);
  const [isAddingItem, setIsAddingItem] = useState(false);

  // Estados para o modal de item
  const [modalStock, setModalStock] = useState(0);
  const [isUploading, setIsUploading] = useState(false);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string>('');

  // Estados para o modal de edição/criação de usuário
  const [editUserName, setEditUserName] = useState('');
  const [editUserId, setEditUserId] = useState('');
  const [editUserPassword, setEditUserPassword] = useState('');

  // Sincroniza o estoque do modal quando o item a editar muda
  useEffect(() => {
    if (itemToEdit) {
      setModalStock(itemToEdit.stock || 0);
      setPreviewUrl(itemToEdit.imageUrl || '');
    } else if (isAddingItem) {
      setModalStock(0);
      setPreviewUrl('');
    }
    setSelectedFile(null);
  }, [itemToEdit, isAddingItem]);

  // Sincroniza os dados do usuário no modal de edição
  useEffect(() => {
    if (userToEdit) {
      setEditUserName(userToEdit.name);
      setEditUserId(userToEdit.corporateId);
      setEditUserPassword(userToEdit.passwordHash);
    } else if (isAddingUser) {
      setEditUserName('');
      setEditUserId('');
      setEditUserPassword('');
    }
  }, [userToEdit, isAddingUser]);

  const economicData = useMemo(() => {
    const rewardItems = db.rewardItems || [];
    const wallets = db.wallets || [];
    const totalStockValue = rewardItems.reduce((acc: number, item: RewardItem) => acc + ((item.cost || 0) * (item.stock || 0)), 0);
    const personalPoints = wallets.reduce((acc: number, w: Wallet) => acc + (w.balance || 0), 0);
    const donationPoints = wallets.reduce((acc: number, w: Wallet) => {
      return acc + ((w.donatableGold || 0) * 3) + ((w.donatableSilver || 0) * 2) + ((w.donatableBronze || 0) * 1);
    }, 0);
    return { totalStockValue, totalDistributedPoints: personalPoints + donationPoints, balanceGap: totalStockValue - (personalPoints + donationPoints) };
  }, [db.rewardItems, db.wallets]);

  // Ranking Olímpico
  const olympicRanking = useMemo(() => {
    const stats: Record<string, { gold: number; silver: number; bronze: number; name: string; corporateId: string }> = {};

    db.users.forEach((u: User) => {
      stats[u.id] = { gold: 0, silver: 0, bronze: 0, name: u.name, corporateId: u.corporateId };
    });

    (db.transactions || []).forEach((t: Transaction) => {
      if (t.type === TransactionType.CREDIT && !t.isDonationVerba && t.coinType && stats[t.toUserId]) {
        if (t.coinType === CoinType.GOLD) stats[t.toUserId].gold++;
        else if (t.coinType === CoinType.SILVER) stats[t.toUserId].silver++;
        else if (t.coinType === CoinType.BRONZE) stats[t.toUserId].bronze++;
      }
    });

    return Object.values(stats).sort((a, b) => {
      if (b.gold !== a.gold) return b.gold - a.gold;
      if (b.silver !== a.silver) return b.silver - a.silver;
      return b.bronze - a.bronze;
    });
  }, [db.transactions, db.users]);

  // --- GESTÃO DE USUÁRIOS ---
  const handleSaveUser = () => {
    if (!editUserName.trim() || !editUserId.trim() || !editUserPassword.trim()) {
      showToast('Preencha todos os campos obrigatórios.', 'warning');
      return;
    }
    const currentDb = getDB();
    const idExists = currentDb.users.some((u: User) => u.corporateId === editUserId && u.id !== userToEdit?.id);
    if (idExists) { showToast('Este ID Corporativo já pertence a outro colaborador.', 'error'); return; }

    if (userToEdit) {
      const userInDb = currentDb.users.find((u: User) => u.id === userToEdit.id);
      if (userInDb) {
        userInDb.name = editUserName; userInDb.corporateId = editUserId; userInDb.passwordHash = editUserPassword;
        showToast('Dados do colaborador atualizados!', 'success');
      }
    } else {
      const newUser: User = {
        id: Math.random().toString(36).substr(2, 9), corporateId: editUserId, name: editUserName,
        passwordHash: editUserPassword, status: UserStatus.ACTIVE, roles: [Role.USER],
        capabilities: [Capability.OPERADOR], createdAt: new Date().toISOString()
      };
      currentDb.users.push(newUser);
      currentDb.wallets.push({ userId: newUser.id, balance: 0, donatableGold: 0, donatableSilver: 0, donatableBronze: 0 });
      showToast(`${editUserName} cadastrado com sucesso!`, 'success');
    }
    saveDB(currentDb); onRefreshDB(); setUserToEdit(null); setIsAddingUser(false);
  };

  const handleAdjustVerba = (targetUser: User, newValue: number) => {
    const currentDb = getDB();
    const wallet = currentDb.wallets.find((w: any) => w.userId === targetUser.id);
    if (!wallet) return;
    let weight = 1; let coinType = CoinType.BRONZE;
    if (targetUser.capabilities.includes(Capability.ADMIN) || targetUser.capabilities.includes(Capability.GERENTE_FABRIL)) { coinType = CoinType.GOLD; weight = 3; }
    else if (targetUser.capabilities.includes(Capability.GERENTE_AREA)) { coinType = CoinType.SILVER; weight = 2; }
    const currentVal = coinType === CoinType.GOLD ? (wallet.donatableGold || 0) : coinType === CoinType.SILVER ? (wallet.donatableSilver || 0) : (wallet.donatableBronze || 0);
    const delta = newValue - currentVal;
    if (delta > 0 && (delta * weight) > economicData.balanceGap) { showToast('Limite de emissão atingido!', 'error'); return; }
    if (coinType === CoinType.GOLD) wallet.donatableGold = Math.max(0, newValue);
    else if (coinType === CoinType.SILVER) wallet.donatableSilver = Math.max(0, newValue);
    else wallet.donatableBronze = Math.max(0, newValue);
    if (delta !== 0) {
      currentDb.transactions.unshift({ id: Math.random().toString(36).substr(2, 9), type: TransactionType.CREDIT, amount: Math.abs(delta * weight), coinType, fromUserId: 'SYSTEM', toUserId: targetUser.id, reason: 'Ajuste Admin Verba', category: 'Administração', createdAt: new Date().toISOString(), createdBy: user.id, isDonationVerba: true });
      saveDB(currentDb); onRefreshDB();
    }
  };

  const handleAdjustSaldo = (targetUser: User, newValue: number) => {
    const currentDb = getDB();
    const wallet = currentDb.wallets.find((w: any) => w.userId === targetUser.id);
    if (!wallet) return;
    const delta = newValue - (wallet.balance || 0);
    if (delta > 0 && delta > economicData.balanceGap) { showToast('Estoque insuficiente!', 'error'); return; }
    wallet.balance = Math.max(0, newValue);
    if (delta !== 0) {
      currentDb.transactions.unshift({ id: Math.random().toString(36).substr(2, 9), type: delta > 0 ? TransactionType.CREDIT : TransactionType.DEBIT, amount: Math.abs(delta), fromUserId: 'SYSTEM', toUserId: targetUser.id, reason: 'Correção de Saldo Admin', category: 'Administração', createdAt: new Date().toISOString(), createdBy: user.id });
      saveDB(currentDb); onRefreshDB();
    }
  };

  const toggleCapability = (u: User, cap: Capability) => {
    const currentDb = getDB();
    const userInDb = currentDb.users.find((user: User) => user.id === u.id);
    if (userInDb) {
      const jobRoles = [Capability.OPERADOR, Capability.SUPERVISOR_COORDENADOR, Capability.GERENTE_AREA, Capability.GERENTE_FABRIL, Capability.GENTE_GESTAO];
      if (jobRoles.includes(cap)) { userInDb.capabilities = userInDb.capabilities.filter(c => !jobRoles.includes(c)); userInDb.capabilities.push(cap); }
      else { if (userInDb.capabilities.includes(cap)) { userInDb.capabilities = userInDb.capabilities.filter(c => c !== cap); } else { userInDb.capabilities.push(cap); } }
      saveDB(currentDb); onRefreshDB(); if (userToEdit) setUserToEdit({ ...userInDb });
    }
  };

  const handleUpdateItemStock = (itemId: string, newStock: number) => {
    const currentDb = getDB(); const item = currentDb.rewardItems.find(i => i.id === itemId);
    if (item) { item.stock = Math.max(0, newStock); saveDB(currentDb); onRefreshDB(); }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) { setSelectedFile(file); setPreviewUrl(URL.createObjectURL(file)); }
  };

  const handleSaveItem = async (e: React.FormEvent) => {
    e.preventDefault(); setIsUploading(true);
    try {
      const formData = new FormData(e.currentTarget as HTMLFormElement);
      let finalImageUrl = itemToEdit?.imageUrl || '';
      if (selectedFile) {
        const fileExt = selectedFile.name.split('.').pop();
        const fileName = `${Math.random().toString(36).substr(2, 9)}.${fileExt}`;
        const filePath = `items/${fileName}`;
        const { error: uploadError } = await supabase.storage.from('reward-images').upload(filePath, selectedFile);
        if (uploadError) throw uploadError;
        const { data: { publicUrl } } = supabase.storage.from('reward-images').getPublicUrl(filePath);
        finalImageUrl = publicUrl;
      }
      const itemData = { name: formData.get('name') as string, description: formData.get('description') as string, imageUrl: finalImageUrl, cost: Number(formData.get('cost')), stock: modalStock, category: formData.get('category') as string, isActive: true };
      const currentDb = getDB();
      if (itemToEdit) { const idx = currentDb.rewardItems.findIndex(i => i.id === itemToEdit.id); currentDb.rewardItems[idx] = { ...itemToEdit, ...itemData }; }
      else { currentDb.rewardItems.push({ ...itemData, id: Math.random().toString(36).substr(2, 9) }); }
      saveDB(currentDb); onRefreshDB(); setItemToEdit(null); setIsAddingItem(false);
    } catch (err: any) { showToast('Erro ao salvar: ' + err.message, 'error'); } finally { setIsUploading(false); }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter leading-none">Painel de Controle</h1>
          <p className="text-zinc-500 text-[10px] font-black uppercase tracking-[0.2em] mt-2 italic">Gestão Econômica e Inventário de Brindes.</p>
        </div>
        <div className="flex gap-2 bg-zinc-900/50 p-2 rounded-2xl w-fit border border-zinc-800 overflow-x-auto no-scrollbar max-w-full">
          <button onClick={() => setActiveTab('USERS')} className={`px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === 'USERS' ? 'bg-yellow-500 text-black shadow-lg shadow-yellow-500/10' : 'text-zinc-500 hover:text-white'}`}>Colaboradores</button>
          <button onClick={() => setActiveTab('ITEMS')} className={`px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === 'ITEMS' ? 'bg-white text-black shadow-lg shadow-white/10' : 'text-zinc-500 hover:text-white'}`}>Estoque</button>
          <button onClick={() => setActiveTab('STATS')} className={`px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === 'STATS' ? 'bg-emerald-500 text-black shadow-lg shadow-emerald-500/10' : 'text-zinc-500 hover:text-white'}`}>Dashboard</button>
        </div>
      </header>

      {/* CARDS ECONÔMICOS */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className={`p-6 rounded-[2rem] border transition-colors ${economicData.balanceGap < 0 ? 'bg-rose-500/10 border-rose-500/20' : 'bg-emerald-500/10 border-emerald-500/20'}`}>
          <p className="text-[9px] font-black text-zinc-500 uppercase tracking-widest mb-1">Capacidade de Emissão (Estoque Livre)</p>
          <div className="flex items-baseline gap-2 text-emerald-500 font-black italic tracking-tighter">
            <span className="text-4xl">{economicData.balanceGap || 0}</span>
            <span className="text-[8px] uppercase">Pts</span>
