export default Admin;

import React, { useState, useMemo, useEffect } from 'react';
import { User, UserStatus, Role, Capability, RewardItem, Wallet, CoinType, TransactionType, Transaction } from '../types';
import { saveDB, addAuditLog, getDB } from '../store';
import { ToastType } from '../components/Toast';
import { supabase } from '../App';

interface AdminProps {
  user: User;
  db: any;
  onRefreshDB: () => void;
  showToast: (msg: string, type: ToastType) => void;
}

const Admin: React.FC<AdminProps> = ({ user, db, onRefreshDB, showToast }) => {
  const [activeTab, setActiveTab] = useState<'USERS' | 'ITEMS' | 'STATS'>('USERS');
  const [userToEdit, setUserToEdit] = useState<User | null>(null);
  const [isAddingUser, setIsAddingUser] = useState(false);
  const [itemToEdit, setItemToEdit] = useState<RewardItem | null>(null);
  const [isAddingItem, setIsAddingItem] = useState(false);

  // Estados para o modal de item
  const [modalStock, setModalStock] = useState(0);
  const [isUploading, setIsUploading] = useState(false);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string>('');

  // Estados para o modal de edição/criação de usuário
  const [editUserName, setEditUserName] = useState('');
  const [editUserId, setEditUserId] = useState('');
  const [editUserPassword, setEditUserPassword] = useState('');

  // Sincroniza o estoque do modal quando o item a editar muda
  useEffect(() => {
    if (itemToEdit) {
      setModalStock(itemToEdit.stock || 0);
      setPreviewUrl(itemToEdit.imageUrl || '');
    } else if (isAddingItem) {
      setModalStock(0);
      setPreviewUrl('');
    }
    setSelectedFile(null);
  }, [itemToEdit, isAddingItem]);

  // Sincroniza os dados do usuário no modal de edição
  useEffect(() => {
    if (userToEdit) {
      setEditUserName(userToEdit.name);
      setEditUserId(userToEdit.corporateId);
      setEditUserPassword(userToEdit.passwordHash);
    } else if (isAddingUser) {
      setEditUserName('');
      setEditUserId('');
      setEditUserPassword('');
    }
  }, [userToEdit, isAddingUser]);

  const economicData = useMemo(() => {
    const rewardItems = db.rewardItems || [];
    const wallets = db.wallets || [];
    const totalStockValue = rewardItems.reduce((acc: number, item: RewardItem) => acc + ((item.cost || 0) * (item.stock || 0)), 0);
    const personalPoints = wallets.reduce((acc: number, w: Wallet) => acc + (w.balance || 0), 0);
    const donationPoints = wallets.reduce((acc: number, w: Wallet) => {
      return acc + ((w.donatableGold || 0) * 3) + ((w.donatableSilver || 0) * 2) + ((w.donatableBronze || 0) * 1);
    }, 0);
    return { totalStockValue, totalDistributedPoints: personalPoints + donationPoints, balanceGap: totalStockValue - (personalPoints + donationPoints) };
  }, [db.rewardItems, db.wallets]);

  // Ranking Olímpico
  const olympicRanking = useMemo(() => {
    const stats: Record<string, { gold: number; silver: number; bronze: number; name: string; corporateId: string }> = {};

    db.users.forEach((u: User) => {
      stats[u.id] = { gold: 0, silver: 0, bronze: 0, name: u.name, corporateId: u.corporateId };
    });

    (db.transactions || []).forEach((t: Transaction) => {
      if (t.type === TransactionType.CREDIT && !t.isDonationVerba && t.coinType && stats[t.toUserId]) {
        if (t.coinType === CoinType.GOLD) stats[t.toUserId].gold++;
        else if (t.coinType === CoinType.SILVER) stats[t.toUserId].silver++;
        else if (t.coinType === CoinType.BRONZE) stats[t.toUserId].bronze++;
      }
    });

    return Object.values(stats).sort((a, b) => {
      if (b.gold !== a.gold) return b.gold - a.gold;
      if (b.silver !== a.silver) return b.silver - a.silver;
      return b.bronze - a.bronze;
    });
  }, [db.transactions, db.users]);

  // Fix: Adding sortedUsers to avoid "Cannot find name 'sortedUsers'" error.
  const sortedUsers = useMemo(() => {
    return [...(db.users || [])].sort((a, b) => a.name.localeCompare(b.name));
  }, [db.users]);

  // --- GESTÃO DE USUÁRIOS ---
  const handleSaveUser = () => {
    if (!editUserName.trim() || !editUserId.trim() || !editUserPassword.trim()) {
      showToast('Preencha todos os campos obrigatórios.', 'warning');
      return;
    }
    const currentDb = getDB();
    const idExists = currentDb.users.some((u: User) => u.corporateId === editUserId && u.id !== userToEdit?.id);
    if (idExists) { showToast('Este ID Corporativo já pertence a outro colaborador.', 'error'); return; }

    if (userToEdit) {
      const userInDb = currentDb.users.find((u: User) => u.id === userToEdit.id);
      if (userInDb) {
        userInDb.name = editUserName; userInDb.corporateId = editUserId; userInDb.passwordHash = editUserPassword;
        showToast('Dados do colaborador atualizados!', 'success');
      }
    } else {
      const newUser: User = {
        id: Math.random().toString(36).substr(2, 9), corporateId: editUserId, name: editUserName,
        passwordHash: editUserPassword, status: UserStatus.ACTIVE, roles: [Role.USER],
        capabilities: [Capability.OPERADOR], createdAt: new Date().toISOString()
      };
      currentDb.users.push(newUser);
      currentDb.wallets.push({ userId: newUser.id, balance: 0, donatableGold: 0, donatableSilver: 0, donatableBronze: 0 });
      showToast(`${editUserName} cadastrado com sucesso!`, 'success');
    }
    saveDB(currentDb); onRefreshDB(); setUserToEdit(null); setIsAddingUser(false);
  };

  const handleAdjustVerba = (targetUser: User, newValue: number) => {
    const currentDb = getDB();
    const wallet = currentDb.wallets.find((w: any) => w.userId === targetUser.id);
    if (!wallet) return;
    let weight = 1; let coinType = CoinType.BRONZE;
    if (targetUser.capabilities.includes(Capability.ADMIN) || targetUser.capabilities.includes(Capability.GERENTE_FABRIL)) { coinType = CoinType.GOLD; weight = 3; }
    else if (targetUser.capabilities.includes(Capability.GERENTE_AREA)) { coinType = CoinType.SILVER; weight = 2; }
    const currentVal = coinType === CoinType.GOLD ? (wallet.donatableGold || 0) : coinType === CoinType.SILVER ? (wallet.donatableSilver || 0) : (wallet.donatableBronze || 0);
    const delta = newValue - currentVal;
    if (delta > 0 && (delta * weight) > economicData.balanceGap) { showToast('Limite de emissão atingido!', 'error'); return; }
    if (coinType === CoinType.GOLD) wallet.donatableGold = Math.max(0, newValue);
    else if (coinType === CoinType.SILVER) wallet.donatableSilver = Math.max(0, newValue);
    else wallet.donatableBronze = Math.max(0, newValue);
    if (delta !== 0) {
      currentDb.transactions.unshift({ id: Math.random().toString(36).substr(2, 9), type: TransactionType.CREDIT, amount: Math.abs(delta * weight), coinType, fromUserId: 'SYSTEM', toUserId: targetUser.id, reason: 'Ajuste Admin Verba', category: 'Administração', createdAt: new Date().toISOString(), createdBy: user.id, isDonationVerba: true });
      saveDB(currentDb); onRefreshDB();
    }
  };

  const handleAdjustSaldo = (targetUser: User, newValue: number) => {
    const currentDb = getDB();
    const wallet = currentDb.wallets.find((w: any) => w.userId === targetUser.id);
    if (!wallet) return;
    const delta = newValue - (wallet.balance || 0);
    if (delta > 0 && delta > economicData.balanceGap) { showToast('Estoque insuficiente!', 'error'); return; }
    wallet.balance = Math.max(0, newValue);
    if (delta !== 0) {
      currentDb.transactions.unshift({ id: Math.random().toString(36).substr(2, 9), type: delta > 0 ? TransactionType.CREDIT : TransactionType.DEBIT, amount: Math.abs(delta), fromUserId: 'SYSTEM', toUserId: targetUser.id, reason: 'Correção de Saldo Admin', category: 'Administração', createdAt: new Date().toISOString(), createdBy: user.id });
      saveDB(currentDb); onRefreshDB();
    }
  };

  const toggleCapability = (u: User, cap: Capability) => {
    const currentDb = getDB();
    const userInDb = currentDb.users.find((user: User) => user.id === u.id);
    if (userInDb) {
      const jobRoles = [Capability.OPERADOR, Capability.SUPERVISOR_COORDENADOR, Capability.GERENTE_AREA, Capability.GERENTE_FABRIL, Capability.GENTE_GESTAO];
      if (jobRoles.includes(cap)) { userInDb.capabilities = userInDb.capabilities.filter(c => !jobRoles.includes(c)); userInDb.capabilities.push(cap); }
      else { if (userInDb.capabilities.includes(cap)) { userInDb.capabilities = userInDb.capabilities.filter(c => c !== cap); } else { userInDb.capabilities.push(cap); } }
      saveDB(currentDb); onRefreshDB(); if (userToEdit) setUserToEdit({ ...userInDb });
    }
  };

  const handleUpdateItemStock = (itemId: string, newStock: number) => {
    const currentDb = getDB(); const item = currentDb.rewardItems.find(i => i.id === itemId);
    if (item) { item.stock = Math.max(0, newStock); saveDB(currentDb); onRefreshDB(); }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) { setSelectedFile(file); setPreviewUrl(URL.createObjectURL(file)); }
  };

  const handleSaveItem = async (e: React.FormEvent) => {
    e.preventDefault(); setIsUploading(true);
    try {
      const formData = new FormData(e.currentTarget as HTMLFormElement);
      let finalImageUrl = itemToEdit?.imageUrl || '';
      if (selectedFile) {
        const fileExt = selectedFile.name.split('.').pop();
        const fileName = `${Math.random().toString(36).substr(2, 9)}.${fileExt}`;
        const filePath = `items/${fileName}`;
        const { error: uploadError } = await supabase.storage.from('reward-images').upload(filePath, selectedFile);
        if (uploadError) throw uploadError;
        const { data: { publicUrl } } = supabase.storage.from('reward-images').getPublicUrl(filePath);
        finalImageUrl = publicUrl;
      }
      const itemData = { name: formData.get('name') as string, description: formData.get('description') as string, imageUrl: finalImageUrl, cost: Number(formData.get('cost')), stock: modalStock, category: formData.get('category') as string, isActive: true };
      const currentDb = getDB();
      if (itemToEdit) { const idx = currentDb.rewardItems.findIndex(i => i.id === itemToEdit.id); currentDb.rewardItems[idx] = { ...itemToEdit, ...itemData }; }
      else { currentDb.rewardItems.push({ ...itemData, id: Math.random().toString(36).substr(2, 9) }); }
      saveDB(currentDb); onRefreshDB(); setItemToEdit(null); setIsAddingItem(false);
    } catch (err: any) { showToast('Erro ao salvar: ' + err.message, 'error'); } finally { setIsUploading(false); }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter leading-none">Painel de Controle</h1>
          <p className="text-zinc-500 text-[10px] font-black uppercase tracking-[0.2em] mt-2 italic">Gestão Econômica e Inventário de Brindes.</p>
        </div>
        <div className="flex gap-2 bg-zinc-900/50 p-2 rounded-2xl w-fit border border-zinc-800 overflow-x-auto no-scrollbar max-w-full">
          <button onClick={() => setActiveTab('USERS')} className={`px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === 'USERS' ? 'bg-yellow-500 text-black shadow-lg shadow-yellow-500/10' : 'text-zinc-500 hover:text-white'}`}>Colaboradores</button>
          <button onClick={() => setActiveTab('ITEMS')} className={`px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === 'ITEMS' ? 'bg-white text-black shadow-lg shadow-white/10' : 'text-zinc-500 hover:text-white'}`}>Estoque</button>
          <button onClick={() => setActiveTab('STATS')} className={`px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === 'STATS' ? 'bg-emerald-500 text-black shadow-lg shadow-emerald-500/10' : 'text-zinc-500 hover:text-white'}`}>Dashboard</button>
        </div>
      </header>

      {/* CARDS ECONÔMICOS */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className={`p-6 rounded-[2rem] border transition-colors ${economicData.balanceGap < 0 ? 'bg-rose-500/10 border-rose-500/20' : 'bg-emerald-500/10 border-emerald-500/20'}`}>
          <p className="text-[9px] font-black text-zinc-500 uppercase tracking-widest mb-1">Capacidade de Emissão (Estoque Livre)</p>
          <div className="flex items-baseline gap-2 text-emerald-500 font-black italic tracking-tighter">
            <span className="text-4xl">{economicData.balanceGap || 0}</span>
            <span className="text-[8px] uppercase">Pts</span>
          </div>
        </div>
        <div className="p-6 rounded-[2rem] bg-zinc-900 border border-zinc-800">
          <p className="text-[9px] font-black text-zinc-500 uppercase tracking-widest mb-1">Passivo (Moedas em Mãos)</p>
          <div className="flex items-baseline gap-2 text-white font-black italic tracking-tighter">
            <span className="text-4xl">{economicData.totalDistributedPoints || 0}</span>
            <span className="text-[8px] uppercase">Pts</span>
          </div>
        </div>
        <div className="p-6 rounded-[2rem] bg-zinc-900 border border-zinc-800">
          <p className="text-[9px] font-black text-zinc-500 uppercase tracking-widest mb-1">Patrimônio Brindes (Total em Itens)</p>
          <div className="flex items-baseline gap-2 text-yellow-500 font-black italic tracking-tighter">
            <span className="text-4xl">{economicData.totalStockValue || 0}</span>
            <span className="text-[8px] uppercase">Pts</span>
          </div>
        </div>
      </div>

      {activeTab === 'USERS' && (
        <div className="bg-zinc-900/40 border border-zinc-800 rounded-[3rem] overflow-hidden">
          <div className="p-8 border-b border-zinc-800 flex justify-between items-center bg-black/20 text-white">
            <h2 className="font-black italic uppercase tracking-tighter text-xl text-white">Lista de Colaboradores</h2>
            <button onClick={() => setIsAddingUser(true)} className="bg-emerald-500 text-black px-6 py-2.5 rounded-xl font-black text-[9px] uppercase tracking-widest hover:bg-emerald-400 transition-all flex items-center gap-2 shadow-lg shadow-emerald-500/10"><i className="fa-solid fa-user-plus"></i> Novo Colaborador</button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-black/40">
                <tr>
                  <th className="px-8 py-5 text-[9px] font-black text-zinc-600 uppercase tracking-[0.2em]">Colaborador</th>
                  <th className="px-8 py-5 text-[9px] font-black text-zinc-600 uppercase tracking-[0.2em] text-center">Verba Liderança</th>
                  <th className="px-8 py-5 text-[9px] font-black text-zinc-600 uppercase tracking-[0.2em] text-center">Saldo Loja</th>
                  <th className="px-8 py-5 text-[9px] font-black text-zinc-600 uppercase tracking-[0.2em] text-right">Ações</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-zinc-800">
                {sortedUsers.map((u: User) => {
                  const wallet = db.wallets.find((w: any) => w.userId === u.id) || { balance: 0, donatableGold: 0, donatableSilver: 0, donatableBronze: 0 };
                  const isLeader = u.capabilities.some(c => [Capability.SUPERVISOR_COORDENADOR, Capability.GERENTE_AREA, Capability.GERENTE_FABRIL, Capability.GENTE_GESTAO, Capability.ADMIN].includes(c));
                  const coinValue = u.capabilities.includes(Capability.ADMIN) || u.capabilities.includes(Capability.GERENTE_FABRIL) ? (wallet.donatableGold || 0) : u.capabilities.includes(Capability.GERENTE_AREA) ? (wallet.donatableSilver || 0) : (wallet.donatableBronze || 0);
                  return (
                    <tr key={u.id} className="hover:bg-white/[0.02] transition-colors">
                      <td className="px-8 py-6">
                        <p className="font-black text-white uppercase italic tracking-tighter leading-none mb-1">{u.name}</p>
                        <span className="text-[9px] text-zinc-600 font-bold uppercase tracking-widest">{u.corporateId}</span>
                      </td>
                      <td className="px-8 py-6 text-center">
                        <div className="flex justify-center">
                          {isLeader ? (
                            <div className="flex items-center bg-black border border-zinc-800 rounded-2xl overflow-hidden p-1 gap-1">
                              <button onClick={() => handleAdjustVerba(u, Math.max(0, coinValue - 1))} className="w-8 h-8 flex items-center justify-center text-zinc-600 hover:text-white"><i className="fa-solid fa-minus text-[10px]"></i></button>
                              <input type="number" className="w-12 bg-transparent text-center text-lg font-black text-yellow-500 italic outline-none" value={coinValue} onChange={(e) => handleAdjustVerba(u, parseInt(e.target.value) || 0)} />
                              <button onClick={() => handleAdjustVerba(u, coinValue + 1)} className="w-8 h-8 flex items-center justify-center text-yellow-500"><i className="fa-solid fa-plus text-[10px]"></i></button>
                            </div>
                          ) : <span className="text-[9px] text-zinc-700 font-black uppercase italic">Sem Perfil Líder</span>}
                        </div>
                      </td>
                      <td className="px-8 py-6 text-center">
                        <div className="flex justify-center">
                          <div className="flex items-center bg-zinc-900 border border-zinc-800 rounded-2xl overflow-hidden p-1 gap-1">
                            <button onClick={() => handleAdjustSaldo(u, Math.max(0, (wallet.balance || 0) - 1))} className="w-8 h-8 flex items-center justify-center text-zinc-600 hover:text-rose-500"><i className="fa-solid fa-minus text-[10px]"></i></button>
                            <input type="number" className="w-16 bg-transparent text-center text-lg font-black text-white italic outline-none" value={wallet.balance || 0} onChange={(e) => handleAdjustSaldo(u, parseInt(e.target.value) || 0)} />
                            <button onClick={() => handleAdjustSaldo(u, (wallet.balance || 0) + 1)} className="w-8 h-8 flex items-center justify-center text-emerald-500"><i className="fa-solid fa-plus text-[10px]"></i></button>
                          </div>
                        </div>
                      </td>
                      <td className="px-8 py-6 text-right">
                        <button onClick={() => setUserToEdit(u)} className="w-10 h-10 rounded-xl bg-zinc-800 text-zinc-500 flex items-center justify-center hover:bg-yellow-500 hover:text-black transition-all"><i className="fa-solid fa-user-gear"></i></button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'ITEMS' && (
        <div className="space-y-6">
          <div className="flex justify-between items-center">
            <h2 className="text-xl font-black text-white italic uppercase tracking-tighter">Catálogo de Brindes</h2>
            <button onClick={() => { setItemToEdit(null); setIsAddingItem(true); }} className="bg-emerald-500 text-black px-6 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-emerald-400 transition-all flex items-center gap-2 shadow-lg shadow-emerald-500/10"><i className="fa-solid fa-plus"></i> Novo Item</button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {db.rewardItems.map((item: RewardItem) => (
              <div key={item.id} className="bg-zinc-900 border border-zinc-800 rounded-[2.5rem] p-6 space-y-4 hover:border-zinc-500 transition-all flex flex-col group">
                 <div className="flex items-center gap-4">
                    <img src={item.imageUrl} className="w-16 h-16 rounded-2xl object-cover grayscale group-hover:grayscale-0 transition-all" />
                    <div className="flex-1 min-w-0">
                       <h4 className="text-sm font-black text-white italic uppercase truncate">{item.name}</h4>
                       <p className="text-[8px] font-bold text-zinc-500 uppercase tracking-widest">{item.category} • {item.cost} pts</p>
                    </div>
                    <button onClick={() => setItemToEdit(item)} className="text-zinc-500 hover:text-white transition-colors"><i className="fa-solid fa-pen-to-square"></i></button>
                 </div>
                 <div className="pt-4 border-t border-zinc-800">
                    <div className="flex items-center justify-between mb-2">
                       <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Estoque</p>
                       <span className={`text-[10px] font-black italic ${item.stock < 5 ? 'text-rose-500' : 'text-emerald-500'}`}>{item.stock} UN</span>
                    </div>
                    <div className="flex items-center bg-black border border-zinc-800 rounded-2xl p-1 gap-1">
                      <button onClick={() => handleUpdateItemStock(item.id, item.stock - 1)} className="w-10 h-10 flex items-center justify-center text-zinc-600 hover:text-rose-500"><i className="fa-solid fa-minus"></i></button>
                      <input type="number" className="flex-1 bg-transparent text-center text-xl font-black text-white italic outline-none" value={item.stock} onChange={(e) => handleUpdateItemStock(item.id, parseInt(e.target.value) || 0)} />
                      <button onClick={() => handleUpdateItemStock(item.id, item.stock + 1)} className="w-10 h-10 flex items-center justify-center text-emerald-500"><i className="fa-solid fa-plus"></i></button>
                    </div>
                 </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'STATS' && (
        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 space-y-8">
           <div className="bg-zinc-900/40 border border-zinc-800 rounded-[3rem] overflow-hidden">
             <div className="p-8 border-b border-zinc-800 flex items-center justify-between bg-black/20 text-white">
                <div>
                  <h2 className="font-black italic uppercase tracking-tighter text-2xl text-white leading-none">Ranking Olímpico</h2>
                  <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest mt-2">Classificação por mérito de moedas recebidas.</p>
                </div>
                <i className="fa-solid fa-medal text-3xl text-yellow-500"></i>
             </div>
             <div className="overflow-x-auto">
               <table className="w-full text-left">
                 <thead className="bg-black/40">
                   <tr>
                     <th className="px-8 py-5 text-[9px] font-black text-zinc-600 uppercase tracking-[0.2em]">Posição</th>
                     <th className="px-8 py-5 text-[9px] font-black text-zinc-600 uppercase tracking-[0.2em]">Colaborador</th>
                     <th className="px-4 py-5 text-[9px] font-black text-yellow-500 uppercase tracking-[0.2em] text-center">Ouro</th>
                     <th className="px-4 py-5 text-[9px] font-black text-zinc-400 uppercase tracking-[0.2em] text-center">Prata</th>
                     <th className="px-4 py-5 text-[9px] font-black text-orange-600 uppercase tracking-[0.2em] text-center">Bronze</th>
                   </tr>
                 </thead>
                 <tbody className="divide-y divide-zinc-800">
                   {olympicRanking.map((rank, index) => (
                     <tr key={rank.corporateId} className={`hover:bg-white/[0.02] transition-colors ${index < 3 ? 'bg-white/[0.01]' : ''}`}>
                       <td className="px-8 py-6">
                         <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black italic ${index === 0 ? 'bg-yellow-500 text-black shadow-lg shadow-yellow-500/20' : index === 1 ? 'bg-zinc-400 text-black shadow-lg shadow-zinc-400/20' : index === 2 ? 'bg-orange-700 text-white shadow-lg shadow-orange-700/20' : 'bg-zinc-800 text-zinc-500'}`}>
                           {index + 1}º
                         </div>
                       </td>
                       <td className="px-8 py-6">
                         <p className="font-black text-white uppercase italic tracking-tighter leading-none mb-1">{rank.name}</p>
                         <span className="text-[9px] text-zinc-600 font-bold uppercase tracking-widest">{rank.corporateId}</span>
                       </td>
                       <td className="px-4 py-6 text-center">
                         <span className="text-2xl font-black text-yellow-500 italic tracking-tighter">{rank.gold}</span>
                       </td>
                       <td className="px-4 py-6 text-center">
                         <span className="text-2xl font-black text-zinc-400 italic tracking-tighter">{rank.silver}</span>
                       </td>
                       <td className="px-4 py-6 text-center">
                         <span className="text-2xl font-black text-orange-600 italic tracking-tighter">{rank.bronze}</span>
                       </td>
                     </tr>
                   ))}
                 </tbody>
               </table>
             </div>
           </div>
        </div>
      )}

      {/* MODAL GESTÃO ITEM (NOVO OU EDITAR) */}
      {(itemToEdit || isAddingItem) && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-xl z-[110] flex items-center justify-center p-4 overflow-y-auto">
          <div className="w-full max-w-xl bg-zinc-900 border border-zinc-800 rounded-[3rem] p-10 shadow-2xl animate-in zoom-in duration-300">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-3xl font-black text-white italic uppercase tracking-tighter">{itemToEdit ? 'Editar Brinde' : 'Novo Brinde'}</h3>
              <button onClick={() => { setItemToEdit(null); setIsAddingItem(false); }} className="w-10 h-10 rounded-full bg-zinc-800 text-zinc-500 flex items-center justify-center hover:text-white transition-colors"><i className="fa-solid fa-xmark"></i></button>
            </div>
            <form onSubmit={handleSaveItem} className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-zinc-500 uppercase ml-1">Nome</label>
                  <input name="name" defaultValue={itemToEdit?.name || ''} required className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl outline-none font-bold" />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-zinc-500 uppercase ml-1">Categoria</label>
                  <input name="category" defaultValue={itemToEdit?.category || ''} required className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl outline-none font-bold" />
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-zinc-500 uppercase ml-1">Foto</label>
                <div className="flex items-center gap-4">
                  <div className="w-24 h-24 rounded-2xl bg-black border border-zinc-800 overflow-hidden flex items-center justify-center">
