                    <div className="w-full p-6 bg-black border-2 border-dashed border-zinc-800 text-zinc-500 rounded-2xl hover:border-yellow-500 text-center uppercase text-[9px] font-black">Selecionar Foto</div>
                    <input type="file" accept="image/*" className="hidden" onChange={handleFileChange} />
                  </label>
