              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-zinc-500 uppercase ml-1">Custo</label>
                  <input type="number" name="cost" defaultValue={itemToEdit?.cost || 10} required className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl outline-none font-black text-xl italic" />
