              <button type="submit" disabled={isUploading} className={`w-full py-5 rounded-[1.5rem] font-black text-xs uppercase tracking-widest transition-all ${isUploading ? 'bg-zinc-800 text-zinc-500' : 'bg-yellow-500 text-black hover:bg-yellow-400'}`}>
                {isUploading ? 'ENVIANDO...' : (itemToEdit ? 'SALVAR ALTERAÇÕES' : 'CADASTRAR BRINDE')}
              </button>
            </form>
          </div>
        </div>
      )}

      {/* MODAL DE GESTÃO DE USUÁRIO */}
      {(userToEdit || isAddingUser) && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-xl z-[100] flex items-center justify-center p-4 overflow-y-auto">
          <div className="w-full max-w-3xl bg-zinc-900 border border-zinc-800 rounded-[3rem] p-8 md:p-12 shadow-2xl animate-in zoom-in duration-300">
            <div className="flex justify-between items-start mb-8">
              <div><h3 className="text-3xl font-black text-white italic uppercase tracking-tighter leading-none">{isAddingUser ? 'Novo Colaborador' : 'Gestão de Colaborador'}</h3></div>
              <button onClick={() => { setUserToEdit(null); setIsAddingUser(false); }} className="w-10 h-10 rounded-full bg-zinc-800 text-zinc-400 flex items-center justify-center"><i className="fa-solid fa-xmark"></i></button>
            </div>
            <div className="space-y-10">
              <div className="space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <p className="text-[8px] font-black text-zinc-600 uppercase tracking-widest ml-2">Nome Completo</p>
                    <input type="text" className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl outline-none font-bold" value={editUserName} onChange={e => setEditUserName(e.target.value)} />
                  </div>
                  <div className="space-y-2">
                    <p className="text-[8px] font-black text-zinc-600 uppercase tracking-widest ml-2">ID Corporativo</p>
                    <input type="text" className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl outline-none font-bold" value={editUserId} onChange={e => setEditUserId(e.target.value)} />
                  </div>
                  <div className="space-y-2 md:col-span-2">
                    <p className="text-[8px] font-black text-zinc-600 uppercase tracking-widest ml-2">Senha</p>
                    <input type="text" className="w-full p-4 bg-black border border-zinc-800 text-white rounded-2xl outline-none font-bold" value={editUserPassword} onChange={e => setEditUserPassword(e.target.value)} />
                  </div>
                </div>
                <button onClick={handleSaveUser} className="w-full px-12 py-4 bg-yellow-500 text-black rounded-2xl font-black text-[11px] uppercase tracking-widest shadow-lg">SALVAR CADASTRO</button>
              </div>
              {!isAddingUser && (
                <div className="space-y-4">
                  <label className="block text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1 italic">Perfil de Acesso</label>
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2">
                    {[Capability.OPERADOR, Capability.SUPERVISOR_COORDENADOR, Capability.GERENTE_AREA, Capability.GERENTE_FABRIL, Capability.GENTE_GESTAO].map(role => (
                      <button key={role} onClick={() => toggleCapability(userToEdit!, role)} className={`px-4 py-4 rounded-2xl border font-black text-[9px] uppercase tracking-widest transition-all ${userToEdit!.capabilities.includes(role) ? 'bg-white text-black border-white' : 'bg-black text-zinc-600 border-zinc-800'}`}>{role}</button>
                    ))}
                  </div>
                </div>
              )}
              <div className="pt-8 border-t border-zinc-800 flex justify-end">
                 <button onClick={() => { setUserToEdit(null); setIsAddingUser(false); }} className="px-12 py-4 bg-zinc-800 text-white rounded-2xl font-black text-xs uppercase tracking-widest">Concluir</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

