  ADMIN = 'ADMIN'
}

export enum Capability {
  RECEIVE_ONLY = 'SOMENTE_RECEBE',
  LEADERSHIP = 'LIDERANÇA',
  APPROVE_PURCHASES = 'APROVAR_RESGATES',
  ADMIN = 'ADMINISTRADOR',
  OPERADOR = 'OPERADOR',
