        <div className="fixed inset-0 bg-black/90 backdrop-blur-xl z-[100] flex items-center justify-center p-4 overflow-y-auto">
          <div className="w-full max-w-3xl bg-zinc-900 border border-zinc-800 rounded-[3rem] p-8 md:p-12 shadow-2xl animate-in zoom-in duration-300">
            <div className="flex justify-between items-start mb-8">
              <div><h3 className="text-3xl font-black text-white italic uppercase tracking-tighter leading-none">{isAddingUser ? 'Novo Colaborador' : 'Gestão de Colaborador'}</h3></div>
