              )}
              <div className="pt-8 border-t border-zinc-800 flex justify-end">
                 <button onClick={() => { setUserToEdit(null); setIsAddingUser(false); }} className="px-12 py-4 bg-zinc-800 text-white rounded-2xl font-black text-xs uppercase tracking-widest">Concluir</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Admin;

